INSERT INTO `producers` (`id`, `title`, `slug`, `description`, `content`, `meta_title`, `meta_keywords`, `meta_description`, `icon`, `banner`, `image_id`, `images`, `index`, `active`, `created_at`, `updated_at`, `deleted_at`) VALUES
	(1, 'Gia Lai', 'gia-lai', '<strong>Gia Lai</strong>&nbsp;l&agrave; một&nbsp;<a href="https://vi.wikipedia.org/wiki/T%E1%BB%89nh_th%C3%A0nh_Vi%E1%BB%87t_Nam" title="Tỉnh thành Việt Nam">tỉnh</a>&nbsp;nằm ở khu vực&nbsp;<a href="https://vi.wikipedia.org/wiki/Duy%C3%AAn_h%E1%BA%A3i_Nam_Trung_B%E1%BB%99" title="Duyên hải Nam Trung Bộ">duy&ecirc;n hải Nam Trung bộ</a>&nbsp;v&agrave;&nbsp;<a href="https://vi.wikipedia.org/wiki/T%C3%A2y_Nguy%C3%AAn" title="Tây Nguyên">T&acirc;y Nguy&ecirc;n</a>,&nbsp;<a href="https://vi.wikipedia.org/wiki/Mi%E1%BB%81n_Trung" title="Miền Trung">miền Trung</a>&nbsp;<a href="https://vi.wikipedia.org/wiki/Vi%E1%BB%87t_Nam" title="Việt Nam">Việt Nam</a>&nbsp;v&agrave; l&agrave; tỉnh c&oacute; diện t&iacute;ch lớn thứ hai&nbsp;<a href="https://vi.wikipedia.org/wiki/Vi%E1%BB%87t_Nam" title="Việt Nam">Việt Nam</a>.<sup><a href="https://vi.wikipedia.org/wiki/Gia_Lai#cite_note-3">[3]</a></sup>&nbsp;<a href="https://vi.wikipedia.org/wiki/T%E1%BB%89nh_l%E1%BB%B5_(Vi%E1%BB%87t_Nam)" title="Tỉnh lỵ (Việt Nam)">Trung t&acirc;m h&agrave;nh ch&iacute;nh</a>&nbsp;của tỉnh l&agrave; phường&nbsp;<a href="https://vi.wikipedia.org/wiki/Quy_Nh%C6%A1n" title="Quy Nhơn">Quy Nhơn</a>.', '<p>Nguồn gốc t&ecirc;n gọi Gia Lai bắt nguồn từ chữ&nbsp;<a href="https://vi.wikipedia.org/wiki/Ng%C6%B0%E1%BB%9Di_Gia_Rai" title="Người Gia Rai">Jarai</a>, t&ecirc;n gọi của một d&acirc;n tộc thiểu số trong tỉnh, c&aacute;ch gọi n&agrave;y vẫn c&ograve;n giữ trong tiếng của người &Ecirc;-đ&ecirc;, Ba Na, L&agrave;o, Th&aacute;i Lan v&agrave; Campuchia để gọi v&ugrave;ng đất n&agrave;y l&agrave; Jarai, Charay c&oacute; nghĩa l&agrave; v&ugrave;ng đất của người Jarai, c&oacute; lẽ &aacute;m chỉ v&ugrave;ng đất của&nbsp;<a href="https://vi.wikipedia.org/wiki/Th%E1%BB%A7y_X%C3%A1" title="Thủy Xá">Thủy X&aacute;</a>&nbsp;v&agrave;&nbsp;<a href="https://vi.wikipedia.org/wiki/H%E1%BB%8Fa_X%C3%A1" title="Hỏa Xá">Hỏa X&aacute;</a>&nbsp;thuộc&nbsp;<a href="https://vi.wikipedia.org/wiki/Ti%E1%BB%83u_qu%E1%BB%91c_Jarai" title="Tiểu quốc Jarai">tiểu quốc Jarai</a>&nbsp;xưa.</p>\r\n\r\n<p>Gia Lai l&agrave; một tỉnh nằm ở cả v&ugrave;ng n&uacute;i v&agrave; ven biển, nằm ở&nbsp;<a href="https://vi.wikipedia.org/wiki/Nam_Trung_B%E1%BB%99" title="Nam Trung Bộ">Nam Trung Bộ</a>&nbsp;với độ cao trung b&igrave;nh từ 700 - 800&nbsp;<a href="https://vi.wikipedia.org/wiki/M%C3%A9t" title="Mét">m&eacute;t</a>&nbsp;so với mực nước biển đối với v&ugrave;ng n&uacute;i v&agrave; 0 - 30&nbsp;<a href="https://vi.wikipedia.org/wiki/M%C3%A9t" title="Mét">m&eacute;t</a>&nbsp;đối với đồng bằng. Gia Lai c&aacute;ch&nbsp;<a href="https://vi.wikipedia.org/wiki/H%C3%A0_N%E1%BB%99i" title="Hà Nội">H&agrave; Nội</a>&nbsp;1.120&nbsp;km, c&aacute;ch&nbsp;<a href="https://vi.wikipedia.org/wiki/%C4%90%C3%A0_N%E1%BA%B5ng" title="Đà Nẵng">Đ&agrave; Nẵng</a>&nbsp;396&nbsp;km, c&aacute;ch&nbsp;<a href="https://vi.wikipedia.org/wiki/Th%C3%A0nh_ph%E1%BB%91_H%E1%BB%93_Ch%C3%AD_Minh" title="Thành phố Hồ Chí Minh">Th&agrave;nh phố Hồ Ch&iacute; Minh</a>&nbsp;491&nbsp;km.</p>\r\n&nbsp;\r\n\r\n<ul>\r\n</ul>\r\n\r\n<h2><br />\r\n<br />\r\n<strong>Đặc sản m&oacute;n ngon Gia lai.&nbsp;</strong></h2>\r\n\r\n<h3>🐄 <strong>B&ograve; một nắng Kr&ocirc;ng Pa</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Thịt b&ograve; phơi đ&uacute;ng 1 nắng, khi nướng l&ecirc;n thơm lừng</p>\r\n	</li>\r\n	<li>\r\n	<p>Chấm <strong>muối kiến v&agrave;ng</strong> chua cay mặn ngọt cực cuốn<br />\r\n	👉 Đ&acirc;y l&agrave; <strong>đặc sản nổi tiếng nhất Gia Lai</strong></p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🐔 <strong>G&agrave; nướng cơm lam</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>G&agrave; thả vườn ướp sả &ndash; mật ong &ndash; l&aacute; rừng</p>\r\n	</li>\r\n	<li>\r\n	<p>Ăn k&egrave;m cơm lam dẻo thơm trong ống tre</p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🐖 <strong>Heo rừng nướng / heo mọi</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Thịt chắc, &iacute;t mỡ</p>\r\n	</li>\r\n	<li>\r\n	<p>Thường nướng than hoặc hấp l&aacute; rừng<br />\r\n	&nbsp;</p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🍜 <strong>Phở kh&ocirc; Gia Lai (phở hai t&ocirc;)</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>1 t&ocirc; b&aacute;nh phở trộn + 1 t&ocirc; nước l&egrave;o ri&ecirc;ng</p>\r\n	</li>\r\n	<li>\r\n	<p>C&oacute; thịt g&agrave; / b&ograve;, h&agrave;nh phi, đậu phộng<br />\r\n	👉 M&oacute;n n&agrave;y người Gia Lai cực tự h&agrave;o lu&ocirc;n 💖</p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🍲 <strong>B&uacute;n mắm cua</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>M&ugrave;i hơi nặng nhưng ăn l&agrave; nghiện</p>\r\n	</li>\r\n	<li>\r\n	<p>C&oacute; da heo, chả, rau sống đầy &uacute; ụ</p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🐜 <strong>Muối kiến v&agrave;ng</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>L&agrave;m từ kiến rừng rang + muối + ớt</p>\r\n	</li>\r\n	<li>\r\n	<p>Chấm b&ograve;, tr&aacute;i c&acirc;y, cơm lam đều ngon</p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🌶 <strong>Muối l&aacute; &eacute;</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Cay thơm đặc trưng</p>\r\n	</li>\r\n	<li>\r\n	<p>Thường ăn k&egrave;m thịt nướng</p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<h2>🍰 ĐẶC SẢN MUA VỀ L&Agrave;M QU&Agrave;</h2>\r\n\r\n<ul>\r\n	<li>\r\n	<p>☕ <strong>C&agrave; ph&ecirc; Pleiku</strong> &ndash; đậm vị, thơm l&acirc;u</p>\r\n	</li>\r\n	<li>\r\n	<p>🍯 <strong>Mật ong rừng Gia Lai</strong></p>\r\n	</li>\r\n	<li>\r\n	<p>🌶 <strong>Ti&ecirc;u Chư S&ecirc;</strong> &ndash; nổi tiếng cả nước</p>\r\n	</li>\r\n	<li>\r\n	<p>🥓 <strong>B&ograve; một nắng đ&oacute;ng g&oacute;i</strong></p>\r\n	</li>\r\n</ul>\r\n\r\n<p>&nbsp;</p>', 'Gia Lai, Biển hồ, Phố núi Tây Nguyên, Món ngon - đặc sản cao nguyên', 'Gia Lai, Pleiku, món ngon núi rừng, đặc sản tây nguyên, phố núi tình yêu', 'Gia Lai nổi bật với vẻ đẹp hùng vĩ của núi rừng và bản sắc văn hóa đặc trưng của các dân tộc thiểu số. Với những món ăn - thức uống đậm chất hoang sơ của núi rừng', NULL, NULL, 19, '24,25', 1, 1, NULL, '2025-12-18 11:23:32', NULL),
	(2, 'Gia Lai', 'gia-lai', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 1, NULL, '2025-10-24 04:09:33', '2025-10-24 04:09:33'),
	(3, 'Gia Lai', 'gia-lai', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 1, NULL, '2025-10-24 04:09:31', '2025-10-24 04:09:31'),
	(4, 'Gia Lai', 'gia-lai', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1, 1, NULL, '2025-10-24 04:09:30', '2025-10-24 04:09:30'),
	(5, 'Bình Định', 'binh-dinh', '<strong>B&igrave;nh Định</strong>&nbsp;l&agrave; một&nbsp;<a href="https://vi.wikipedia.org/wiki/T%E1%BB%89nh_(Vi%E1%BB%87t_Nam)" title="Tỉnh (Việt Nam)">tỉnh</a>&nbsp;cũ ven biển nằm ở ph&iacute;a bắc v&ugrave;ng&nbsp;<a href="https://vi.wikipedia.org/wiki/Duy%C3%AAn_h%E1%BA%A3i_Nam_Trung_B%E1%BB%99" title="Duyên hải Nam Trung Bộ">Duy&ecirc;n hải Nam Trung Bộ</a>,&nbsp;<a href="https://vi.wikipedia.org/wiki/Trung_B%E1%BB%99" title="Trung Bộ">miền Trung</a>,&nbsp;<a href="https://vi.wikipedia.org/wiki/Vi%E1%BB%87t_Nam" title="Việt Nam">Việt Nam</a>. Ng&agrave;y&nbsp;<a href="https://vi.wikipedia.org/wiki/12_th%C3%A1ng_6" title="12 tháng 6">12 th&aacute;ng 6</a>&nbsp;năm 2025,&nbsp;<a href="https://vi.wikipedia.org/wiki/Qu%E1%BB%91c_h%E1%BB%99i_Vi%E1%BB%87t_Nam" title="Quốc hội Việt Nam">Quốc hội</a>&nbsp;th&ocirc;ng qua Nghị quyết số 202/2025/QH15 về việc sắp xếp đơn vị h&agrave;nh ch&iacute;nh cấp tỉnh năm 2025, theo đ&oacute; tỉnh được giải thể để s&aacute;p nhập v&agrave;o tỉnh&nbsp;<a href="https://vi.wikipedia.org/wiki/Gia_Lai" title="Gia Lai">Gia Lai</a>', '<p>Ngo&agrave;i c&aacute;c đặc sản về l&acirc;m, thổ, thủy, hải sản của duy&ecirc;n hải miền Trung n&oacute;i chung,<br />\r\nB&igrave;nh Định c&ograve;n c&oacute;:&nbsp;<a href="https://vi.wikipedia.org/wiki/R%C6%B0%E1%BB%A3u_B%C3%A0u_%C4%90%C3%A1" title="Rượu Bàu Đá">rượu B&agrave;u Đ&aacute;</a>&nbsp;(<a href="https://vi.wikipedia.org/wiki/An_Nh%C6%A1n" title="An Nhơn">An Nhơn</a>).<br />\r\nC&aacute; chua nước lợ (Đề Gi -&nbsp;<a href="https://vi.wikipedia.org/wiki/Ph%C3%B9_C%C3%A1t" title="Phù Cát">Ph&ugrave; C&aacute;t</a>).<br />\r\nB&aacute;nh tr&aacute;ng nước dừa (<a href="https://vi.wikipedia.org/wiki/Tam_Quan,_Ho%C3%A0i_Nh%C6%A1n" title="Tam Quan, Hoài Nhơn">phường Tam Quan</a>).<br />\r\nB&uacute;n Song Thằn v&agrave; B&aacute;nh hỏi.<br />\r\nNem chả Chợ Huyện, B&aacute;nh &iacute;t l&aacute; gai.<br />\r\n<br />\r\nNg&agrave;y nay ở thị x&atilde; Ho&agrave;i Nhơn c&oacute; th&ecirc;m đặc sản&nbsp;<a href="https://vi.wikipedia.org/wiki/C%C3%A1_ng%E1%BB%AB_%C4%91%E1%BA%A1i_d%C6%B0%C6%A1ng" title="Cá ngừ đại dương">c&aacute; ngừ đại dương</a>&nbsp;(c&aacute; &quot;B&ograve; G&ugrave;&quot;), thị x&atilde; An Nhơn c&oacute; th&ecirc;m Rượu Vang Nếp Belifoods.<br />\r\n<br />\r\n<br />\r\n<br />\r\n<br />\r\n<strong>M&oacute;n ăn nhiều người ưa th&iacute;ch Tại đ&acirc;y</strong><br />\r\n<br />\r\n🦐 <strong>B&uacute;n chả c&aacute; Quy Nhơn</strong></p>\r\n\r\n<p>Chả c&aacute; thu, c&aacute; mối dai &ndash; ngọt</p>\r\n\r\n<p>Nước d&ugrave;ng trong, thanh, kh&ocirc;ng ngấy<br />\r\n&nbsp;</p>\r\n\r\n<h3>🍜 <strong>B&uacute;n c&aacute; ngừ</strong></h3>\r\n\r\n<p>C&aacute; ngừ tươi, miếng to</p>\r\n\r\n<p>Nước d&ugrave;ng ngọt tự nhi&ecirc;n, &iacute;t dầu mỡ</p>\r\n\r\n<h3>🥣 <strong>Ch&aacute;o l&ograve;ng &ndash; b&aacute;nh hỏi l&ograve;ng heo</strong></h3>\r\n&nbsp;\r\n\r\n<p>B&aacute;nh hỏi mềm + l&ograve;ng luộc n&oacute;ng hổi</p>\r\n\r\n<p>Chấm mắm ớt B&igrave;nh Định cay nồng 🌶<br />\r\n&nbsp;</p>\r\n\r\n<h3>🥟 <strong>B&aacute;nh x&egrave;o t&ocirc;m nhảy</strong></h3>\r\n\r\n<p>T&ocirc;m tươi nhảy tanh t&aacute;ch</p>\r\n\r\n<p>B&aacute;nh nhỏ, gi&ograve;n, ăn k&egrave;m rau sống &amp; b&aacute;nh tr&aacute;ng<br />\r\n&nbsp;</p>\r\n\r\n<h3>🥮 <strong>B&aacute;nh &iacute;t l&aacute; gai</strong></h3>\r\n\r\n<p>Nh&acirc;n dừa hoặc đậu xanh</p>\r\n\r\n<p>Dẻo thơm, hơi ngọt &ndash; rất hợp mua l&agrave;m qu&agrave;<br />\r\n&nbsp;</p>\r\n\r\n<h3>🥠 <strong>B&aacute;nh hồng Tam Quan</strong></h3>\r\n\r\n<p>Dẻo &ndash; ngọt &ndash; thơm m&ugrave;i dừa</p>\r\n\r\n<p>Đặc sản truyền thống trong cưới hỏi</p>\r\n\r\n<h3>🐟 <strong>Chả c&aacute; Quy Nhơn</strong></h3>\r\n\r\n<p>L&agrave;m từ c&aacute; biển tươi</p>\r\n\r\n<p>Chi&ecirc;n hay hấp đều ngon<br />\r\n&nbsp;</p>\r\n\r\n<h3>🦀 <strong>Cua Huỳnh Đế</strong></h3>\r\n\r\n<p>Cua to, thịt chắc, gạch b&eacute;o</p>\r\n\r\n<p>Hấp đơn giản l&agrave; ngon nhất 😍<br />\r\n&nbsp;</p>\r\n\r\n<h3>🌶 <strong>Mắm nhum &ndash; mắm c&aacute;</strong></h3>\r\n\r\n<p>Mặn m&ograve;i, đ&uacute;ng vị biển</p>\r\n\r\n<p>Ăn với b&aacute;nh tr&aacute;ng &amp; rau sống<br />\r\n&nbsp;</p>\r\n\r\n<h2>🎁 ĐẶC SẢN MUA VỀ L&Agrave;M QU&Agrave;</h2>\r\n\r\n<p>🥮 B&aacute;nh &iacute;t l&aacute; gai</p>\r\n\r\n<p>🥠 B&aacute;nh hồng Tam Quan</p>\r\n\r\n<p>🐟 Chả c&aacute; Quy Nhơn</p>\r\n\r\n<p>🌶 Mắm c&aacute; &ndash; mắm nhum</p>', 'Bình định, Quy nhơn, Món ngon - đặc sản - hải sản của duyên hải miền Trung.', 'Bình định, món ngon duyên hải miền trung, đặc sản - hải sản ven biển, bánh tráng, rượu bàu đá', 'Bình định có đặc sản - hải sản của duyên hải miền Trung, rượu bàu đá, bánh tráng nước dừa , bún và bánh hỏi, nem chả Chợ Huyện, bánh ít lá gai, cá ngừ đại dương, Rượu Vang Nếp Belifoods.', NULL, NULL, 23, NULL, 1, 1, NULL, '2025-12-18 02:52:20', NULL),
	(6, 'Quảng ngãi', 'quang-ngai', '<strong>Gia Lai</strong>&nbsp;l&agrave; một&nbsp;<a href="https://vi.wikipedia.org/wiki/T%E1%BB%89nh_th%C3%A0nh_Vi%E1%BB%87t_Nam" title="Tỉnh thành Việt Nam">tỉnh</a>&nbsp;nằm ở khu vực&nbsp;<a href="https://vi.wikipedia.org/wiki/Duy%C3%AAn_h%E1%BA%A3i_Nam_Trung_B%E1%BB%99" title="Duyên hải Nam Trung Bộ">duy&ecirc;n hải Nam Trung bộ</a>&nbsp;v&agrave;&nbsp;<a href="https://vi.wikipedia.org/wiki/T%C3%A2y_Nguy%C3%AAn" title="Tây Nguyên">T&acirc;y Nguy&ecirc;n</a>,&nbsp;<a href="https://vi.wikipedia.org/wiki/Mi%E1%BB%81n_Trung" title="Miền Trung">miền Trung</a>&nbsp;<a href="https://vi.wikipedia.org/wiki/Vi%E1%BB%87t_Nam" title="Việt Nam">Việt Nam</a>&nbsp;v&agrave; l&agrave; tỉnh c&oacute; diện t&iacute;ch lớn thứ hai&nbsp;<a href="https://vi.wikipedia.org/wiki/Vi%E1%BB%87t_Nam" title="Việt Nam">Việt Nam</a>.<sup><a href="https://vi.wikipedia.org/wiki/Gia_Lai#cite_note-3">[3]</a></sup>&nbsp;<a href="https://vi.wikipedia.org/wiki/T%E1%BB%89nh_l%E1%BB%B5_(Vi%E1%BB%87t_Nam)" title="Tỉnh lỵ (Việt Nam)">Trung t&acirc;m h&agrave;nh ch&iacute;nh</a>&nbsp;của tỉnh l&agrave; phường&nbsp;<a href="https://vi.wikipedia.org/wiki/Quy_Nh%C6%A1n" title="Quy Nhơn">Quy Nhơn</a>.', '<p>Nguồn gốc t&ecirc;n gọi Gia Lai bắt nguồn từ chữ&nbsp;<a href="https://vi.wikipedia.org/wiki/Ng%C6%B0%E1%BB%9Di_Gia_Rai" title="Người Gia Rai">Jarai</a>, t&ecirc;n gọi của một d&acirc;n tộc thiểu số trong tỉnh, c&aacute;ch gọi n&agrave;y vẫn c&ograve;n giữ trong tiếng của người &Ecirc;-đ&ecirc;, Ba Na, L&agrave;o, Th&aacute;i Lan v&agrave; Campuchia để gọi v&ugrave;ng đất n&agrave;y l&agrave; Jarai, Charay c&oacute; nghĩa l&agrave; v&ugrave;ng đất của người Jarai, c&oacute; lẽ &aacute;m chỉ v&ugrave;ng đất của&nbsp;<a href="https://vi.wikipedia.org/wiki/Th%E1%BB%A7y_X%C3%A1" title="Thủy Xá">Thủy X&aacute;</a>&nbsp;v&agrave;&nbsp;<a href="https://vi.wikipedia.org/wiki/H%E1%BB%8Fa_X%C3%A1" title="Hỏa Xá">Hỏa X&aacute;</a>&nbsp;thuộc&nbsp;<a href="https://vi.wikipedia.org/wiki/Ti%E1%BB%83u_qu%E1%BB%91c_Jarai" title="Tiểu quốc Jarai">tiểu quốc Jarai</a>&nbsp;xưa.</p>\r\n\r\n<p>Gia Lai l&agrave; một tỉnh nằm ở cả v&ugrave;ng n&uacute;i v&agrave; ven biển, nằm ở&nbsp;<a href="https://vi.wikipedia.org/wiki/Nam_Trung_B%E1%BB%99" title="Nam Trung Bộ">Nam Trung Bộ</a>&nbsp;với độ cao trung b&igrave;nh từ 700 - 800&nbsp;<a href="https://vi.wikipedia.org/wiki/M%C3%A9t" title="Mét">m&eacute;t</a>&nbsp;so với mực nước biển đối với v&ugrave;ng n&uacute;i v&agrave; 0 - 30&nbsp;<a href="https://vi.wikipedia.org/wiki/M%C3%A9t" title="Mét">m&eacute;t</a>&nbsp;đối với đồng bằng. Gia Lai c&aacute;ch&nbsp;<a href="https://vi.wikipedia.org/wiki/H%C3%A0_N%E1%BB%99i" title="Hà Nội">H&agrave; Nội</a>&nbsp;1.120&nbsp;km, c&aacute;ch&nbsp;<a href="https://vi.wikipedia.org/wiki/%C4%90%C3%A0_N%E1%BA%B5ng" title="Đà Nẵng">Đ&agrave; Nẵng</a>&nbsp;396&nbsp;km, c&aacute;ch&nbsp;<a href="https://vi.wikipedia.org/wiki/Th%C3%A0nh_ph%E1%BB%91_H%E1%BB%93_Ch%C3%AD_Minh" title="Thành phố Hồ Chí Minh">Th&agrave;nh phố Hồ Ch&iacute; Minh</a>&nbsp;491&nbsp;km.</p>\r\n\r\n<ul>\r\n	<li>Ph&iacute;a đ&ocirc;ng gi&aacute;p&nbsp;<a href="https://vi.wikipedia.org/wiki/Bi%E1%BB%83n_%C4%90%C3%B4ng" title="Biển Đông">Biển Đ&ocirc;ng</a></li>\r\n	<li>Ph&iacute;a t&acirc;y gi&aacute;p tỉnh&nbsp;<a href="https://vi.wikipedia.org/wiki/Ratanakiri" title="Ratanakiri">Ratanakiri</a>,&nbsp;<a href="https://vi.wikipedia.org/wiki/Campuchia" title="Campuchia">Campuchia</a></li>\r\n	<li>Ph&iacute;a nam gi&aacute;p tỉnh&nbsp;<a href="https://vi.wikipedia.org/wiki/%C4%90%E1%BA%AFk_L%E1%BA%AFk" title="Đắk Lắk">Đắk Lắk</a></li>\r\n	<li>Ph&iacute;a bắc gi&aacute;p tỉnh&nbsp;<a href="https://vi.wikipedia.org/wiki/Qu%E1%BA%A3ng_Ng%C3%A3i" title="Quảng Ngãi">Quảng Ng&atilde;i</a>.</li>\r\n</ul>\r\n\r\n<h2><br />\r\nĐặc sản m&oacute;n ngon Gia lai.&nbsp;</h2>\r\n\r\n<h3>🐄 <strong>B&ograve; một nắng Kr&ocirc;ng Pa</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Thịt b&ograve; phơi đ&uacute;ng 1 nắng, khi nướng l&ecirc;n thơm lừng</p>\r\n	</li>\r\n	<li>\r\n	<p>Chấm <strong>muối kiến v&agrave;ng</strong> chua cay mặn ngọt cực cuốn<br />\r\n	👉 Đ&acirc;y l&agrave; <strong>đặc sản nổi tiếng nhất Gia Lai</strong></p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🐔 <strong>G&agrave; nướng cơm lam</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>G&agrave; thả vườn ướp sả &ndash; mật ong &ndash; l&aacute; rừng</p>\r\n	</li>\r\n	<li>\r\n	<p>Ăn k&egrave;m cơm lam dẻo thơm trong ống tre</p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🐖 <strong>Heo rừng nướng / heo mọi</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Thịt chắc, &iacute;t mỡ</p>\r\n	</li>\r\n	<li>\r\n	<p>Thường nướng than hoặc hấp l&aacute; rừng</p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<h2>🍜 M&Oacute;N NƯỚC &ndash; B&Uacute;N &ndash; PHỞ</h2>\r\n\r\n<h3>🍜 <strong>Phở kh&ocirc; Gia Lai (phở hai t&ocirc;)</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>1 t&ocirc; b&aacute;nh phở trộn + 1 t&ocirc; nước l&egrave;o ri&ecirc;ng</p>\r\n	</li>\r\n	<li>\r\n	<p>C&oacute; thịt g&agrave; / b&ograve;, h&agrave;nh phi, đậu phộng<br />\r\n	👉 M&oacute;n n&agrave;y người Gia Lai cực tự h&agrave;o lu&ocirc;n 💖</p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🍲 <strong>B&uacute;n mắm cua</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>M&ugrave;i hơi nặng nhưng ăn l&agrave; nghiện</p>\r\n	</li>\r\n	<li>\r\n	<p>C&oacute; da heo, chả, rau sống đầy &uacute; ụ</p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<h2>🧂 M&Oacute;N CHẤM &ndash; ĂN VẶT</h2>\r\n\r\n<h3>🐜 <strong>Muối kiến v&agrave;ng</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>L&agrave;m từ kiến rừng rang + muối + ớt</p>\r\n	</li>\r\n	<li>\r\n	<p>Chấm b&ograve;, tr&aacute;i c&acirc;y, cơm lam đều ngon</p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🌶 <strong>Muối l&aacute; &eacute;</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Cay thơm đặc trưng</p>\r\n	</li>\r\n	<li>\r\n	<p>Thường ăn k&egrave;m thịt nướng</p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<h2>🍰 ĐẶC SẢN MUA VỀ L&Agrave;M QU&Agrave;</h2>\r\n\r\n<ul>\r\n	<li>\r\n	<p>☕ <strong>C&agrave; ph&ecirc; Pleiku</strong> &ndash; đậm vị, thơm l&acirc;u</p>\r\n	</li>\r\n	<li>\r\n	<p>🍯 <strong>Mật ong rừng Gia Lai</strong></p>\r\n	</li>\r\n	<li>\r\n	<p>🌶 <strong>Ti&ecirc;u Chư S&ecirc;</strong> &ndash; nổi tiếng cả nước</p>\r\n	</li>\r\n	<li>\r\n	<p>🥓 <strong>B&ograve; một nắng đ&oacute;ng g&oacute;i</strong></p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<p>Nếu bạn muốn m&igrave;nh:</p>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Gợi &yacute; <strong>qu&aacute;n ăn ngon ở Pleiku</strong></p>\r\n	</li>\r\n	<li>\r\n	<p>Hay chọn <strong>đặc sản dễ mang đi xa</strong></p>\r\n	</li>\r\n	<li>\r\n	<p>Hoặc ăn theo kiểu <strong>địa phương &iacute;t người biết</strong></p>\r\n	</li>\r\n</ul>', 'Gia Lai, Biển hồ, Phố núi Tây Nguyên, Món ngon - đặc sản cao nguyên', 'Gia Lai, Pleiku, món ngon núi rừng, đặc sản tây nguyên, phố núi tình yêu', 'Gia Lai nổi bật với vẻ đẹp hùng vĩ của núi rừng và bản sắc văn hóa đặc trưng của các dân tộc thiểu số. Với những món ăn - thức uống đậm chất hoang sơ của núi rừng', NULL, NULL, 40, NULL, 1, 1, NULL, '2025-12-18 11:17:04', NULL),
	(7, 'Đà Nẵng', 'da-nang', '<strong>Gia Lai</strong>&nbsp;l&agrave; một&nbsp;<a href="https://vi.wikipedia.org/wiki/T%E1%BB%89nh_th%C3%A0nh_Vi%E1%BB%87t_Nam" title="Tỉnh thành Việt Nam">tỉnh</a>&nbsp;nằm ở khu vực&nbsp;<a href="https://vi.wikipedia.org/wiki/Duy%C3%AAn_h%E1%BA%A3i_Nam_Trung_B%E1%BB%99" title="Duyên hải Nam Trung Bộ">duy&ecirc;n hải Nam Trung bộ</a>&nbsp;v&agrave;&nbsp;<a href="https://vi.wikipedia.org/wiki/T%C3%A2y_Nguy%C3%AAn" title="Tây Nguyên">T&acirc;y Nguy&ecirc;n</a>,&nbsp;<a href="https://vi.wikipedia.org/wiki/Mi%E1%BB%81n_Trung" title="Miền Trung">miền Trung</a>&nbsp;<a href="https://vi.wikipedia.org/wiki/Vi%E1%BB%87t_Nam" title="Việt Nam">Việt Nam</a>&nbsp;v&agrave; l&agrave; tỉnh c&oacute; diện t&iacute;ch lớn thứ hai&nbsp;<a href="https://vi.wikipedia.org/wiki/Vi%E1%BB%87t_Nam" title="Việt Nam">Việt Nam</a>.<sup><a href="https://vi.wikipedia.org/wiki/Gia_Lai#cite_note-3">[3]</a></sup>&nbsp;<a href="https://vi.wikipedia.org/wiki/T%E1%BB%89nh_l%E1%BB%B5_(Vi%E1%BB%87t_Nam)" title="Tỉnh lỵ (Việt Nam)">Trung t&acirc;m h&agrave;nh ch&iacute;nh</a>&nbsp;của tỉnh l&agrave; phường&nbsp;<a href="https://vi.wikipedia.org/wiki/Quy_Nh%C6%A1n" title="Quy Nhơn">Quy Nhơn</a>.', '<p>Nguồn gốc t&ecirc;n gọi Gia Lai bắt nguồn từ chữ&nbsp;<a href="https://vi.wikipedia.org/wiki/Ng%C6%B0%E1%BB%9Di_Gia_Rai" title="Người Gia Rai">Jarai</a>, t&ecirc;n gọi của một d&acirc;n tộc thiểu số trong tỉnh, c&aacute;ch gọi n&agrave;y vẫn c&ograve;n giữ trong tiếng của người &Ecirc;-đ&ecirc;, Ba Na, L&agrave;o, Th&aacute;i Lan v&agrave; Campuchia để gọi v&ugrave;ng đất n&agrave;y l&agrave; Jarai, Charay c&oacute; nghĩa l&agrave; v&ugrave;ng đất của người Jarai, c&oacute; lẽ &aacute;m chỉ v&ugrave;ng đất của&nbsp;<a href="https://vi.wikipedia.org/wiki/Th%E1%BB%A7y_X%C3%A1" title="Thủy Xá">Thủy X&aacute;</a>&nbsp;v&agrave;&nbsp;<a href="https://vi.wikipedia.org/wiki/H%E1%BB%8Fa_X%C3%A1" title="Hỏa Xá">Hỏa X&aacute;</a>&nbsp;thuộc&nbsp;<a href="https://vi.wikipedia.org/wiki/Ti%E1%BB%83u_qu%E1%BB%91c_Jarai" title="Tiểu quốc Jarai">tiểu quốc Jarai</a>&nbsp;xưa.</p>\r\n\r\n<p>Gia Lai l&agrave; một tỉnh nằm ở cả v&ugrave;ng n&uacute;i v&agrave; ven biển, nằm ở&nbsp;<a href="https://vi.wikipedia.org/wiki/Nam_Trung_B%E1%BB%99" title="Nam Trung Bộ">Nam Trung Bộ</a>&nbsp;với độ cao trung b&igrave;nh từ 700 - 800&nbsp;<a href="https://vi.wikipedia.org/wiki/M%C3%A9t" title="Mét">m&eacute;t</a>&nbsp;so với mực nước biển đối với v&ugrave;ng n&uacute;i v&agrave; 0 - 30&nbsp;<a href="https://vi.wikipedia.org/wiki/M%C3%A9t" title="Mét">m&eacute;t</a>&nbsp;đối với đồng bằng. Gia Lai c&aacute;ch&nbsp;<a href="https://vi.wikipedia.org/wiki/H%C3%A0_N%E1%BB%99i" title="Hà Nội">H&agrave; Nội</a>&nbsp;1.120&nbsp;km, c&aacute;ch&nbsp;<a href="https://vi.wikipedia.org/wiki/%C4%90%C3%A0_N%E1%BA%B5ng" title="Đà Nẵng">Đ&agrave; Nẵng</a>&nbsp;396&nbsp;km, c&aacute;ch&nbsp;<a href="https://vi.wikipedia.org/wiki/Th%C3%A0nh_ph%E1%BB%91_H%E1%BB%93_Ch%C3%AD_Minh" title="Thành phố Hồ Chí Minh">Th&agrave;nh phố Hồ Ch&iacute; Minh</a>&nbsp;491&nbsp;km.</p>\r\n\r\n<ul>\r\n	<li>Ph&iacute;a đ&ocirc;ng gi&aacute;p&nbsp;<a href="https://vi.wikipedia.org/wiki/Bi%E1%BB%83n_%C4%90%C3%B4ng" title="Biển Đông">Biển Đ&ocirc;ng</a></li>\r\n	<li>Ph&iacute;a t&acirc;y gi&aacute;p tỉnh&nbsp;<a href="https://vi.wikipedia.org/wiki/Ratanakiri" title="Ratanakiri">Ratanakiri</a>,&nbsp;<a href="https://vi.wikipedia.org/wiki/Campuchia" title="Campuchia">Campuchia</a></li>\r\n	<li>Ph&iacute;a nam gi&aacute;p tỉnh&nbsp;<a href="https://vi.wikipedia.org/wiki/%C4%90%E1%BA%AFk_L%E1%BA%AFk" title="Đắk Lắk">Đắk Lắk</a></li>\r\n	<li>Ph&iacute;a bắc gi&aacute;p tỉnh&nbsp;<a href="https://vi.wikipedia.org/wiki/Qu%E1%BA%A3ng_Ng%C3%A3i" title="Quảng Ngãi">Quảng Ng&atilde;i</a>.</li>\r\n</ul>\r\n\r\n<h2><br />\r\nĐặc sản m&oacute;n ngon Gia lai.&nbsp;</h2>\r\n\r\n<h3>🐄 <strong>B&ograve; một nắng Kr&ocirc;ng Pa</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Thịt b&ograve; phơi đ&uacute;ng 1 nắng, khi nướng l&ecirc;n thơm lừng</p>\r\n	</li>\r\n	<li>\r\n	<p>Chấm <strong>muối kiến v&agrave;ng</strong> chua cay mặn ngọt cực cuốn<br />\r\n	👉 Đ&acirc;y l&agrave; <strong>đặc sản nổi tiếng nhất Gia Lai</strong></p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🐔 <strong>G&agrave; nướng cơm lam</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>G&agrave; thả vườn ướp sả &ndash; mật ong &ndash; l&aacute; rừng</p>\r\n	</li>\r\n	<li>\r\n	<p>Ăn k&egrave;m cơm lam dẻo thơm trong ống tre</p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🐖 <strong>Heo rừng nướng / heo mọi</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Thịt chắc, &iacute;t mỡ</p>\r\n	</li>\r\n	<li>\r\n	<p>Thường nướng than hoặc hấp l&aacute; rừng</p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<h2>🍜 M&Oacute;N NƯỚC &ndash; B&Uacute;N &ndash; PHỞ</h2>\r\n\r\n<h3>🍜 <strong>Phở kh&ocirc; Gia Lai (phở hai t&ocirc;)</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>1 t&ocirc; b&aacute;nh phở trộn + 1 t&ocirc; nước l&egrave;o ri&ecirc;ng</p>\r\n	</li>\r\n	<li>\r\n	<p>C&oacute; thịt g&agrave; / b&ograve;, h&agrave;nh phi, đậu phộng<br />\r\n	👉 M&oacute;n n&agrave;y người Gia Lai cực tự h&agrave;o lu&ocirc;n 💖</p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🍲 <strong>B&uacute;n mắm cua</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>M&ugrave;i hơi nặng nhưng ăn l&agrave; nghiện</p>\r\n	</li>\r\n	<li>\r\n	<p>C&oacute; da heo, chả, rau sống đầy &uacute; ụ</p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<h2>🧂 M&Oacute;N CHẤM &ndash; ĂN VẶT</h2>\r\n\r\n<h3>🐜 <strong>Muối kiến v&agrave;ng</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>L&agrave;m từ kiến rừng rang + muối + ớt</p>\r\n	</li>\r\n	<li>\r\n	<p>Chấm b&ograve;, tr&aacute;i c&acirc;y, cơm lam đều ngon</p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🌶 <strong>Muối l&aacute; &eacute;</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Cay thơm đặc trưng</p>\r\n	</li>\r\n	<li>\r\n	<p>Thường ăn k&egrave;m thịt nướng</p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<h2>🍰 ĐẶC SẢN MUA VỀ L&Agrave;M QU&Agrave;</h2>\r\n\r\n<ul>\r\n	<li>\r\n	<p>☕ <strong>C&agrave; ph&ecirc; Pleiku</strong> &ndash; đậm vị, thơm l&acirc;u</p>\r\n	</li>\r\n	<li>\r\n	<p>🍯 <strong>Mật ong rừng Gia Lai</strong></p>\r\n	</li>\r\n	<li>\r\n	<p>🌶 <strong>Ti&ecirc;u Chư S&ecirc;</strong> &ndash; nổi tiếng cả nước</p>\r\n	</li>\r\n	<li>\r\n	<p>🥓 <strong>B&ograve; một nắng đ&oacute;ng g&oacute;i</strong></p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<p>Nếu bạn muốn m&igrave;nh:</p>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Gợi &yacute; <strong>qu&aacute;n ăn ngon ở Pleiku</strong></p>\r\n	</li>\r\n	<li>\r\n	<p>Hay chọn <strong>đặc sản dễ mang đi xa</strong></p>\r\n	</li>\r\n	<li>\r\n	<p>Hoặc ăn theo kiểu <strong>địa phương &iacute;t người biết</strong></p>\r\n	</li>\r\n</ul>', 'Gia Lai, Biển hồ, Phố núi Tây Nguyên, Món ngon - đặc sản cao nguyên', 'Gia Lai, Pleiku, món ngon núi rừng, đặc sản tây nguyên, phố núi tình yêu', 'Gia Lai nổi bật với vẻ đẹp hùng vĩ của núi rừng và bản sắc văn hóa đặc trưng của các dân tộc thiểu số. Với những món ăn - thức uống đậm chất hoang sơ của núi rừng', NULL, NULL, 41, NULL, 1, 1, NULL, '2025-12-18 11:17:55', NULL),
	(8, 'Huế', 'huế', '<strong>Gia Lai</strong>&nbsp;l&agrave; một&nbsp;<a href="https://vi.wikipedia.org/wiki/T%E1%BB%89nh_th%C3%A0nh_Vi%E1%BB%87t_Nam" title="Tỉnh thành Việt Nam">tỉnh</a>&nbsp;nằm ở khu vực&nbsp;<a href="https://vi.wikipedia.org/wiki/Duy%C3%AAn_h%E1%BA%A3i_Nam_Trung_B%E1%BB%99" title="Duyên hải Nam Trung Bộ">duy&ecirc;n hải Nam Trung bộ</a>&nbsp;v&agrave;&nbsp;<a href="https://vi.wikipedia.org/wiki/T%C3%A2y_Nguy%C3%AAn" title="Tây Nguyên">T&acirc;y Nguy&ecirc;n</a>,&nbsp;<a href="https://vi.wikipedia.org/wiki/Mi%E1%BB%81n_Trung" title="Miền Trung">miền Trung</a>&nbsp;<a href="https://vi.wikipedia.org/wiki/Vi%E1%BB%87t_Nam" title="Việt Nam">Việt Nam</a>&nbsp;v&agrave; l&agrave; tỉnh c&oacute; diện t&iacute;ch lớn thứ hai&nbsp;<a href="https://vi.wikipedia.org/wiki/Vi%E1%BB%87t_Nam" title="Việt Nam">Việt Nam</a>.<sup><a href="https://vi.wikipedia.org/wiki/Gia_Lai#cite_note-3">[3]</a></sup>&nbsp;<a href="https://vi.wikipedia.org/wiki/T%E1%BB%89nh_l%E1%BB%B5_(Vi%E1%BB%87t_Nam)" title="Tỉnh lỵ (Việt Nam)">Trung t&acirc;m h&agrave;nh ch&iacute;nh</a>&nbsp;của tỉnh l&agrave; phường&nbsp;<a href="https://vi.wikipedia.org/wiki/Quy_Nh%C6%A1n" title="Quy Nhơn">Quy Nhơn</a>.', '<p>Nguồn gốc t&ecirc;n gọi Gia Lai bắt nguồn từ chữ&nbsp;<a href="https://vi.wikipedia.org/wiki/Ng%C6%B0%E1%BB%9Di_Gia_Rai" title="Người Gia Rai">Jarai</a>, t&ecirc;n gọi của một d&acirc;n tộc thiểu số trong tỉnh, c&aacute;ch gọi n&agrave;y vẫn c&ograve;n giữ trong tiếng của người &Ecirc;-đ&ecirc;, Ba Na, L&agrave;o, Th&aacute;i Lan v&agrave; Campuchia để gọi v&ugrave;ng đất n&agrave;y l&agrave; Jarai, Charay c&oacute; nghĩa l&agrave; v&ugrave;ng đất của người Jarai, c&oacute; lẽ &aacute;m chỉ v&ugrave;ng đất của&nbsp;<a href="https://vi.wikipedia.org/wiki/Th%E1%BB%A7y_X%C3%A1" title="Thủy Xá">Thủy X&aacute;</a>&nbsp;v&agrave;&nbsp;<a href="https://vi.wikipedia.org/wiki/H%E1%BB%8Fa_X%C3%A1" title="Hỏa Xá">Hỏa X&aacute;</a>&nbsp;thuộc&nbsp;<a href="https://vi.wikipedia.org/wiki/Ti%E1%BB%83u_qu%E1%BB%91c_Jarai" title="Tiểu quốc Jarai">tiểu quốc Jarai</a>&nbsp;xưa.</p>\r\n\r\n<p>Gia Lai l&agrave; một tỉnh nằm ở cả v&ugrave;ng n&uacute;i v&agrave; ven biển, nằm ở&nbsp;<a href="https://vi.wikipedia.org/wiki/Nam_Trung_B%E1%BB%99" title="Nam Trung Bộ">Nam Trung Bộ</a>&nbsp;với độ cao trung b&igrave;nh từ 700 - 800&nbsp;<a href="https://vi.wikipedia.org/wiki/M%C3%A9t" title="Mét">m&eacute;t</a>&nbsp;so với mực nước biển đối với v&ugrave;ng n&uacute;i v&agrave; 0 - 30&nbsp;<a href="https://vi.wikipedia.org/wiki/M%C3%A9t" title="Mét">m&eacute;t</a>&nbsp;đối với đồng bằng. Gia Lai c&aacute;ch&nbsp;<a href="https://vi.wikipedia.org/wiki/H%C3%A0_N%E1%BB%99i" title="Hà Nội">H&agrave; Nội</a>&nbsp;1.120&nbsp;km, c&aacute;ch&nbsp;<a href="https://vi.wikipedia.org/wiki/%C4%90%C3%A0_N%E1%BA%B5ng" title="Đà Nẵng">Đ&agrave; Nẵng</a>&nbsp;396&nbsp;km, c&aacute;ch&nbsp;<a href="https://vi.wikipedia.org/wiki/Th%C3%A0nh_ph%E1%BB%91_H%E1%BB%93_Ch%C3%AD_Minh" title="Thành phố Hồ Chí Minh">Th&agrave;nh phố Hồ Ch&iacute; Minh</a>&nbsp;491&nbsp;km.</p>\r\n\r\n<ul>\r\n	<li>Ph&iacute;a đ&ocirc;ng gi&aacute;p&nbsp;<a href="https://vi.wikipedia.org/wiki/Bi%E1%BB%83n_%C4%90%C3%B4ng" title="Biển Đông">Biển Đ&ocirc;ng</a></li>\r\n	<li>Ph&iacute;a t&acirc;y gi&aacute;p tỉnh&nbsp;<a href="https://vi.wikipedia.org/wiki/Ratanakiri" title="Ratanakiri">Ratanakiri</a>,&nbsp;<a href="https://vi.wikipedia.org/wiki/Campuchia" title="Campuchia">Campuchia</a></li>\r\n	<li>Ph&iacute;a nam gi&aacute;p tỉnh&nbsp;<a href="https://vi.wikipedia.org/wiki/%C4%90%E1%BA%AFk_L%E1%BA%AFk" title="Đắk Lắk">Đắk Lắk</a></li>\r\n	<li>Ph&iacute;a bắc gi&aacute;p tỉnh&nbsp;<a href="https://vi.wikipedia.org/wiki/Qu%E1%BA%A3ng_Ng%C3%A3i" title="Quảng Ngãi">Quảng Ng&atilde;i</a>.</li>\r\n</ul>\r\n\r\n<h2><br />\r\nĐặc sản m&oacute;n ngon Gia lai.&nbsp;</h2>\r\n\r\n<h3>🐄 <strong>B&ograve; một nắng Kr&ocirc;ng Pa</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Thịt b&ograve; phơi đ&uacute;ng 1 nắng, khi nướng l&ecirc;n thơm lừng</p>\r\n	</li>\r\n	<li>\r\n	<p>Chấm <strong>muối kiến v&agrave;ng</strong> chua cay mặn ngọt cực cuốn<br />\r\n	👉 Đ&acirc;y l&agrave; <strong>đặc sản nổi tiếng nhất Gia Lai</strong></p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🐔 <strong>G&agrave; nướng cơm lam</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>G&agrave; thả vườn ướp sả &ndash; mật ong &ndash; l&aacute; rừng</p>\r\n	</li>\r\n	<li>\r\n	<p>Ăn k&egrave;m cơm lam dẻo thơm trong ống tre</p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🐖 <strong>Heo rừng nướng / heo mọi</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Thịt chắc, &iacute;t mỡ</p>\r\n	</li>\r\n	<li>\r\n	<p>Thường nướng than hoặc hấp l&aacute; rừng</p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<h2>🍜 M&Oacute;N NƯỚC &ndash; B&Uacute;N &ndash; PHỞ</h2>\r\n\r\n<h3>🍜 <strong>Phở kh&ocirc; Gia Lai (phở hai t&ocirc;)</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>1 t&ocirc; b&aacute;nh phở trộn + 1 t&ocirc; nước l&egrave;o ri&ecirc;ng</p>\r\n	</li>\r\n	<li>\r\n	<p>C&oacute; thịt g&agrave; / b&ograve;, h&agrave;nh phi, đậu phộng<br />\r\n	👉 M&oacute;n n&agrave;y người Gia Lai cực tự h&agrave;o lu&ocirc;n 💖</p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🍲 <strong>B&uacute;n mắm cua</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>M&ugrave;i hơi nặng nhưng ăn l&agrave; nghiện</p>\r\n	</li>\r\n	<li>\r\n	<p>C&oacute; da heo, chả, rau sống đầy &uacute; ụ</p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<h2>🧂 M&Oacute;N CHẤM &ndash; ĂN VẶT</h2>\r\n\r\n<h3>🐜 <strong>Muối kiến v&agrave;ng</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>L&agrave;m từ kiến rừng rang + muối + ớt</p>\r\n	</li>\r\n	<li>\r\n	<p>Chấm b&ograve;, tr&aacute;i c&acirc;y, cơm lam đều ngon</p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🌶 <strong>Muối l&aacute; &eacute;</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Cay thơm đặc trưng</p>\r\n	</li>\r\n	<li>\r\n	<p>Thường ăn k&egrave;m thịt nướng</p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<h2>🍰 ĐẶC SẢN MUA VỀ L&Agrave;M QU&Agrave;</h2>\r\n\r\n<ul>\r\n	<li>\r\n	<p>☕ <strong>C&agrave; ph&ecirc; Pleiku</strong> &ndash; đậm vị, thơm l&acirc;u</p>\r\n	</li>\r\n	<li>\r\n	<p>🍯 <strong>Mật ong rừng Gia Lai</strong></p>\r\n	</li>\r\n	<li>\r\n	<p>🌶 <strong>Ti&ecirc;u Chư S&ecirc;</strong> &ndash; nổi tiếng cả nước</p>\r\n	</li>\r\n	<li>\r\n	<p>🥓 <strong>B&ograve; một nắng đ&oacute;ng g&oacute;i</strong></p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<p>Nếu bạn muốn m&igrave;nh:</p>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Gợi &yacute; <strong>qu&aacute;n ăn ngon ở Pleiku</strong></p>\r\n	</li>\r\n	<li>\r\n	<p>Hay chọn <strong>đặc sản dễ mang đi xa</strong></p>\r\n	</li>\r\n	<li>\r\n	<p>Hoặc ăn theo kiểu <strong>địa phương &iacute;t người biết</strong></p>\r\n	</li>\r\n</ul>', 'Gia Lai, Biển hồ, Phố núi Tây Nguyên, Món ngon - đặc sản cao nguyên', 'Gia Lai, Pleiku, món ngon núi rừng, đặc sản tây nguyên, phố núi tình yêu', 'Gia Lai nổi bật với vẻ đẹp hùng vĩ của núi rừng và bản sắc văn hóa đặc trưng của các dân tộc thiểu số. Với những món ăn - thức uống đậm chất hoang sơ của núi rừng', NULL, NULL, 42, NULL, 1, 1, NULL, NULL, NULL),
	(9, 'Quảng Bình', 'quang-binh', '<strong>Gia Lai</strong>&nbsp;l&agrave; một&nbsp;<a href="https://vi.wikipedia.org/wiki/T%E1%BB%89nh_th%C3%A0nh_Vi%E1%BB%87t_Nam" title="Tỉnh thành Việt Nam">tỉnh</a>&nbsp;nằm ở khu vực&nbsp;<a href="https://vi.wikipedia.org/wiki/Duy%C3%AAn_h%E1%BA%A3i_Nam_Trung_B%E1%BB%99" title="Duyên hải Nam Trung Bộ">duy&ecirc;n hải Nam Trung bộ</a>&nbsp;v&agrave;&nbsp;<a href="https://vi.wikipedia.org/wiki/T%C3%A2y_Nguy%C3%AAn" title="Tây Nguyên">T&acirc;y Nguy&ecirc;n</a>,&nbsp;<a href="https://vi.wikipedia.org/wiki/Mi%E1%BB%81n_Trung" title="Miền Trung">miền Trung</a>&nbsp;<a href="https://vi.wikipedia.org/wiki/Vi%E1%BB%87t_Nam" title="Việt Nam">Việt Nam</a>&nbsp;v&agrave; l&agrave; tỉnh c&oacute; diện t&iacute;ch lớn thứ hai&nbsp;<a href="https://vi.wikipedia.org/wiki/Vi%E1%BB%87t_Nam" title="Việt Nam">Việt Nam</a>.<sup><a href="https://vi.wikipedia.org/wiki/Gia_Lai#cite_note-3">[3]</a></sup>&nbsp;<a href="https://vi.wikipedia.org/wiki/T%E1%BB%89nh_l%E1%BB%B5_(Vi%E1%BB%87t_Nam)" title="Tỉnh lỵ (Việt Nam)">Trung t&acirc;m h&agrave;nh ch&iacute;nh</a>&nbsp;của tỉnh l&agrave; phường&nbsp;<a href="https://vi.wikipedia.org/wiki/Quy_Nh%C6%A1n" title="Quy Nhơn">Quy Nhơn</a>.', '<p>Nguồn gốc t&ecirc;n gọi Gia Lai bắt nguồn từ chữ&nbsp;<a href="https://vi.wikipedia.org/wiki/Ng%C6%B0%E1%BB%9Di_Gia_Rai" title="Người Gia Rai">Jarai</a>, t&ecirc;n gọi của một d&acirc;n tộc thiểu số trong tỉnh, c&aacute;ch gọi n&agrave;y vẫn c&ograve;n giữ trong tiếng của người &Ecirc;-đ&ecirc;, Ba Na, L&agrave;o, Th&aacute;i Lan v&agrave; Campuchia để gọi v&ugrave;ng đất n&agrave;y l&agrave; Jarai, Charay c&oacute; nghĩa l&agrave; v&ugrave;ng đất của người Jarai, c&oacute; lẽ &aacute;m chỉ v&ugrave;ng đất của&nbsp;<a href="https://vi.wikipedia.org/wiki/Th%E1%BB%A7y_X%C3%A1" title="Thủy Xá">Thủy X&aacute;</a>&nbsp;v&agrave;&nbsp;<a href="https://vi.wikipedia.org/wiki/H%E1%BB%8Fa_X%C3%A1" title="Hỏa Xá">Hỏa X&aacute;</a>&nbsp;thuộc&nbsp;<a href="https://vi.wikipedia.org/wiki/Ti%E1%BB%83u_qu%E1%BB%91c_Jarai" title="Tiểu quốc Jarai">tiểu quốc Jarai</a>&nbsp;xưa.</p>\r\n\r\n<p>Gia Lai l&agrave; một tỉnh nằm ở cả v&ugrave;ng n&uacute;i v&agrave; ven biển, nằm ở&nbsp;<a href="https://vi.wikipedia.org/wiki/Nam_Trung_B%E1%BB%99" title="Nam Trung Bộ">Nam Trung Bộ</a>&nbsp;với độ cao trung b&igrave;nh từ 700 - 800&nbsp;<a href="https://vi.wikipedia.org/wiki/M%C3%A9t" title="Mét">m&eacute;t</a>&nbsp;so với mực nước biển đối với v&ugrave;ng n&uacute;i v&agrave; 0 - 30&nbsp;<a href="https://vi.wikipedia.org/wiki/M%C3%A9t" title="Mét">m&eacute;t</a>&nbsp;đối với đồng bằng. Gia Lai c&aacute;ch&nbsp;<a href="https://vi.wikipedia.org/wiki/H%C3%A0_N%E1%BB%99i" title="Hà Nội">H&agrave; Nội</a>&nbsp;1.120&nbsp;km, c&aacute;ch&nbsp;<a href="https://vi.wikipedia.org/wiki/%C4%90%C3%A0_N%E1%BA%B5ng" title="Đà Nẵng">Đ&agrave; Nẵng</a>&nbsp;396&nbsp;km, c&aacute;ch&nbsp;<a href="https://vi.wikipedia.org/wiki/Th%C3%A0nh_ph%E1%BB%91_H%E1%BB%93_Ch%C3%AD_Minh" title="Thành phố Hồ Chí Minh">Th&agrave;nh phố Hồ Ch&iacute; Minh</a>&nbsp;491&nbsp;km.</p>\r\n\r\n<ul>\r\n	<li>Ph&iacute;a đ&ocirc;ng gi&aacute;p&nbsp;<a href="https://vi.wikipedia.org/wiki/Bi%E1%BB%83n_%C4%90%C3%B4ng" title="Biển Đông">Biển Đ&ocirc;ng</a></li>\r\n	<li>Ph&iacute;a t&acirc;y gi&aacute;p tỉnh&nbsp;<a href="https://vi.wikipedia.org/wiki/Ratanakiri" title="Ratanakiri">Ratanakiri</a>,&nbsp;<a href="https://vi.wikipedia.org/wiki/Campuchia" title="Campuchia">Campuchia</a></li>\r\n	<li>Ph&iacute;a nam gi&aacute;p tỉnh&nbsp;<a href="https://vi.wikipedia.org/wiki/%C4%90%E1%BA%AFk_L%E1%BA%AFk" title="Đắk Lắk">Đắk Lắk</a></li>\r\n	<li>Ph&iacute;a bắc gi&aacute;p tỉnh&nbsp;<a href="https://vi.wikipedia.org/wiki/Qu%E1%BA%A3ng_Ng%C3%A3i" title="Quảng Ngãi">Quảng Ng&atilde;i</a>.</li>\r\n</ul>\r\n\r\n<h2><br />\r\nĐặc sản m&oacute;n ngon Gia lai.&nbsp;</h2>\r\n\r\n<h3>🐄 <strong>B&ograve; một nắng Kr&ocirc;ng Pa</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Thịt b&ograve; phơi đ&uacute;ng 1 nắng, khi nướng l&ecirc;n thơm lừng</p>\r\n	</li>\r\n	<li>\r\n	<p>Chấm <strong>muối kiến v&agrave;ng</strong> chua cay mặn ngọt cực cuốn<br />\r\n	👉 Đ&acirc;y l&agrave; <strong>đặc sản nổi tiếng nhất Gia Lai</strong></p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🐔 <strong>G&agrave; nướng cơm lam</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>G&agrave; thả vườn ướp sả &ndash; mật ong &ndash; l&aacute; rừng</p>\r\n	</li>\r\n	<li>\r\n	<p>Ăn k&egrave;m cơm lam dẻo thơm trong ống tre</p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🐖 <strong>Heo rừng nướng / heo mọi</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Thịt chắc, &iacute;t mỡ</p>\r\n	</li>\r\n	<li>\r\n	<p>Thường nướng than hoặc hấp l&aacute; rừng</p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<h2>🍜 M&Oacute;N NƯỚC &ndash; B&Uacute;N &ndash; PHỞ</h2>\r\n\r\n<h3>🍜 <strong>Phở kh&ocirc; Gia Lai (phở hai t&ocirc;)</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>1 t&ocirc; b&aacute;nh phở trộn + 1 t&ocirc; nước l&egrave;o ri&ecirc;ng</p>\r\n	</li>\r\n	<li>\r\n	<p>C&oacute; thịt g&agrave; / b&ograve;, h&agrave;nh phi, đậu phộng<br />\r\n	👉 M&oacute;n n&agrave;y người Gia Lai cực tự h&agrave;o lu&ocirc;n 💖</p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🍲 <strong>B&uacute;n mắm cua</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>M&ugrave;i hơi nặng nhưng ăn l&agrave; nghiện</p>\r\n	</li>\r\n	<li>\r\n	<p>C&oacute; da heo, chả, rau sống đầy &uacute; ụ</p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<h2>🧂 M&Oacute;N CHẤM &ndash; ĂN VẶT</h2>\r\n\r\n<h3>🐜 <strong>Muối kiến v&agrave;ng</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>L&agrave;m từ kiến rừng rang + muối + ớt</p>\r\n	</li>\r\n	<li>\r\n	<p>Chấm b&ograve;, tr&aacute;i c&acirc;y, cơm lam đều ngon</p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🌶 <strong>Muối l&aacute; &eacute;</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Cay thơm đặc trưng</p>\r\n	</li>\r\n	<li>\r\n	<p>Thường ăn k&egrave;m thịt nướng</p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<h2>🍰 ĐẶC SẢN MUA VỀ L&Agrave;M QU&Agrave;</h2>\r\n\r\n<ul>\r\n	<li>\r\n	<p>☕ <strong>C&agrave; ph&ecirc; Pleiku</strong> &ndash; đậm vị, thơm l&acirc;u</p>\r\n	</li>\r\n	<li>\r\n	<p>🍯 <strong>Mật ong rừng Gia Lai</strong></p>\r\n	</li>\r\n	<li>\r\n	<p>🌶 <strong>Ti&ecirc;u Chư S&ecirc;</strong> &ndash; nổi tiếng cả nước</p>\r\n	</li>\r\n	<li>\r\n	<p>🥓 <strong>B&ograve; một nắng đ&oacute;ng g&oacute;i</strong></p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<p>Nếu bạn muốn m&igrave;nh:</p>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Gợi &yacute; <strong>qu&aacute;n ăn ngon ở Pleiku</strong></p>\r\n	</li>\r\n	<li>\r\n	<p>Hay chọn <strong>đặc sản dễ mang đi xa</strong></p>\r\n	</li>\r\n	<li>\r\n	<p>Hoặc ăn theo kiểu <strong>địa phương &iacute;t người biết</strong></p>\r\n	</li>\r\n</ul>', 'Gia Lai, Biển hồ, Phố núi Tây Nguyên, Món ngon - đặc sản cao nguyên', 'Gia Lai, Pleiku, món ngon núi rừng, đặc sản tây nguyên, phố núi tình yêu', 'Gia Lai nổi bật với vẻ đẹp hùng vĩ của núi rừng và bản sắc văn hóa đặc trưng của các dân tộc thiểu số. Với những món ăn - thức uống đậm chất hoang sơ của núi rừng', NULL, NULL, 43, NULL, 1, 1, NULL, NULL, NULL),
	(10, 'Bình thuận', 'binh-thuan', '<strong>Gia Lai</strong>&nbsp;l&agrave; một&nbsp;<a href="https://vi.wikipedia.org/wiki/T%E1%BB%89nh_th%C3%A0nh_Vi%E1%BB%87t_Nam" title="Tỉnh thành Việt Nam">tỉnh</a>&nbsp;nằm ở khu vực&nbsp;<a href="https://vi.wikipedia.org/wiki/Duy%C3%AAn_h%E1%BA%A3i_Nam_Trung_B%E1%BB%99" title="Duyên hải Nam Trung Bộ">duy&ecirc;n hải Nam Trung bộ</a>&nbsp;v&agrave;&nbsp;<a href="https://vi.wikipedia.org/wiki/T%C3%A2y_Nguy%C3%AAn" title="Tây Nguyên">T&acirc;y Nguy&ecirc;n</a>,&nbsp;<a href="https://vi.wikipedia.org/wiki/Mi%E1%BB%81n_Trung" title="Miền Trung">miền Trung</a>&nbsp;<a href="https://vi.wikipedia.org/wiki/Vi%E1%BB%87t_Nam" title="Việt Nam">Việt Nam</a>&nbsp;v&agrave; l&agrave; tỉnh c&oacute; diện t&iacute;ch lớn thứ hai&nbsp;<a href="https://vi.wikipedia.org/wiki/Vi%E1%BB%87t_Nam" title="Việt Nam">Việt Nam</a>.<sup><a href="https://vi.wikipedia.org/wiki/Gia_Lai#cite_note-3">[3]</a></sup>&nbsp;<a href="https://vi.wikipedia.org/wiki/T%E1%BB%89nh_l%E1%BB%B5_(Vi%E1%BB%87t_Nam)" title="Tỉnh lỵ (Việt Nam)">Trung t&acirc;m h&agrave;nh ch&iacute;nh</a>&nbsp;của tỉnh l&agrave; phường&nbsp;<a href="https://vi.wikipedia.org/wiki/Quy_Nh%C6%A1n" title="Quy Nhơn">Quy Nhơn</a>.', '<p>Nguồn gốc t&ecirc;n gọi Gia Lai bắt nguồn từ chữ&nbsp;<a href="https://vi.wikipedia.org/wiki/Ng%C6%B0%E1%BB%9Di_Gia_Rai" title="Người Gia Rai">Jarai</a>, t&ecirc;n gọi của một d&acirc;n tộc thiểu số trong tỉnh, c&aacute;ch gọi n&agrave;y vẫn c&ograve;n giữ trong tiếng của người &Ecirc;-đ&ecirc;, Ba Na, L&agrave;o, Th&aacute;i Lan v&agrave; Campuchia để gọi v&ugrave;ng đất n&agrave;y l&agrave; Jarai, Charay c&oacute; nghĩa l&agrave; v&ugrave;ng đất của người Jarai, c&oacute; lẽ &aacute;m chỉ v&ugrave;ng đất của&nbsp;<a href="https://vi.wikipedia.org/wiki/Th%E1%BB%A7y_X%C3%A1" title="Thủy Xá">Thủy X&aacute;</a>&nbsp;v&agrave;&nbsp;<a href="https://vi.wikipedia.org/wiki/H%E1%BB%8Fa_X%C3%A1" title="Hỏa Xá">Hỏa X&aacute;</a>&nbsp;thuộc&nbsp;<a href="https://vi.wikipedia.org/wiki/Ti%E1%BB%83u_qu%E1%BB%91c_Jarai" title="Tiểu quốc Jarai">tiểu quốc Jarai</a>&nbsp;xưa.</p>\r\n\r\n<p>Gia Lai l&agrave; một tỉnh nằm ở cả v&ugrave;ng n&uacute;i v&agrave; ven biển, nằm ở&nbsp;<a href="https://vi.wikipedia.org/wiki/Nam_Trung_B%E1%BB%99" title="Nam Trung Bộ">Nam Trung Bộ</a>&nbsp;với độ cao trung b&igrave;nh từ 700 - 800&nbsp;<a href="https://vi.wikipedia.org/wiki/M%C3%A9t" title="Mét">m&eacute;t</a>&nbsp;so với mực nước biển đối với v&ugrave;ng n&uacute;i v&agrave; 0 - 30&nbsp;<a href="https://vi.wikipedia.org/wiki/M%C3%A9t" title="Mét">m&eacute;t</a>&nbsp;đối với đồng bằng. Gia Lai c&aacute;ch&nbsp;<a href="https://vi.wikipedia.org/wiki/H%C3%A0_N%E1%BB%99i" title="Hà Nội">H&agrave; Nội</a>&nbsp;1.120&nbsp;km, c&aacute;ch&nbsp;<a href="https://vi.wikipedia.org/wiki/%C4%90%C3%A0_N%E1%BA%B5ng" title="Đà Nẵng">Đ&agrave; Nẵng</a>&nbsp;396&nbsp;km, c&aacute;ch&nbsp;<a href="https://vi.wikipedia.org/wiki/Th%C3%A0nh_ph%E1%BB%91_H%E1%BB%93_Ch%C3%AD_Minh" title="Thành phố Hồ Chí Minh">Th&agrave;nh phố Hồ Ch&iacute; Minh</a>&nbsp;491&nbsp;km.</p>\r\n\r\n<ul>\r\n	<li>Ph&iacute;a đ&ocirc;ng gi&aacute;p&nbsp;<a href="https://vi.wikipedia.org/wiki/Bi%E1%BB%83n_%C4%90%C3%B4ng" title="Biển Đông">Biển Đ&ocirc;ng</a></li>\r\n	<li>Ph&iacute;a t&acirc;y gi&aacute;p tỉnh&nbsp;<a href="https://vi.wikipedia.org/wiki/Ratanakiri" title="Ratanakiri">Ratanakiri</a>,&nbsp;<a href="https://vi.wikipedia.org/wiki/Campuchia" title="Campuchia">Campuchia</a></li>\r\n	<li>Ph&iacute;a nam gi&aacute;p tỉnh&nbsp;<a href="https://vi.wikipedia.org/wiki/%C4%90%E1%BA%AFk_L%E1%BA%AFk" title="Đắk Lắk">Đắk Lắk</a></li>\r\n	<li>Ph&iacute;a bắc gi&aacute;p tỉnh&nbsp;<a href="https://vi.wikipedia.org/wiki/Qu%E1%BA%A3ng_Ng%C3%A3i" title="Quảng Ngãi">Quảng Ng&atilde;i</a>.</li>\r\n</ul>\r\n\r\n<h2><br />\r\nĐặc sản m&oacute;n ngon Gia lai.&nbsp;</h2>\r\n\r\n<h3>🐄 <strong>B&ograve; một nắng Kr&ocirc;ng Pa</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Thịt b&ograve; phơi đ&uacute;ng 1 nắng, khi nướng l&ecirc;n thơm lừng</p>\r\n	</li>\r\n	<li>\r\n	<p>Chấm <strong>muối kiến v&agrave;ng</strong> chua cay mặn ngọt cực cuốn<br />\r\n	👉 Đ&acirc;y l&agrave; <strong>đặc sản nổi tiếng nhất Gia Lai</strong></p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🐔 <strong>G&agrave; nướng cơm lam</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>G&agrave; thả vườn ướp sả &ndash; mật ong &ndash; l&aacute; rừng</p>\r\n	</li>\r\n	<li>\r\n	<p>Ăn k&egrave;m cơm lam dẻo thơm trong ống tre</p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🐖 <strong>Heo rừng nướng / heo mọi</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Thịt chắc, &iacute;t mỡ</p>\r\n	</li>\r\n	<li>\r\n	<p>Thường nướng than hoặc hấp l&aacute; rừng</p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<h2>🍜 M&Oacute;N NƯỚC &ndash; B&Uacute;N &ndash; PHỞ</h2>\r\n\r\n<h3>🍜 <strong>Phở kh&ocirc; Gia Lai (phở hai t&ocirc;)</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>1 t&ocirc; b&aacute;nh phở trộn + 1 t&ocirc; nước l&egrave;o ri&ecirc;ng</p>\r\n	</li>\r\n	<li>\r\n	<p>C&oacute; thịt g&agrave; / b&ograve;, h&agrave;nh phi, đậu phộng<br />\r\n	👉 M&oacute;n n&agrave;y người Gia Lai cực tự h&agrave;o lu&ocirc;n 💖</p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🍲 <strong>B&uacute;n mắm cua</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>M&ugrave;i hơi nặng nhưng ăn l&agrave; nghiện</p>\r\n	</li>\r\n	<li>\r\n	<p>C&oacute; da heo, chả, rau sống đầy &uacute; ụ</p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<h2>🧂 M&Oacute;N CHẤM &ndash; ĂN VẶT</h2>\r\n\r\n<h3>🐜 <strong>Muối kiến v&agrave;ng</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>L&agrave;m từ kiến rừng rang + muối + ớt</p>\r\n	</li>\r\n	<li>\r\n	<p>Chấm b&ograve;, tr&aacute;i c&acirc;y, cơm lam đều ngon</p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🌶 <strong>Muối l&aacute; &eacute;</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Cay thơm đặc trưng</p>\r\n	</li>\r\n	<li>\r\n	<p>Thường ăn k&egrave;m thịt nướng</p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<h2>🍰 ĐẶC SẢN MUA VỀ L&Agrave;M QU&Agrave;</h2>\r\n\r\n<ul>\r\n	<li>\r\n	<p>☕ <strong>C&agrave; ph&ecirc; Pleiku</strong> &ndash; đậm vị, thơm l&acirc;u</p>\r\n	</li>\r\n	<li>\r\n	<p>🍯 <strong>Mật ong rừng Gia Lai</strong></p>\r\n	</li>\r\n	<li>\r\n	<p>🌶 <strong>Ti&ecirc;u Chư S&ecirc;</strong> &ndash; nổi tiếng cả nước</p>\r\n	</li>\r\n	<li>\r\n	<p>🥓 <strong>B&ograve; một nắng đ&oacute;ng g&oacute;i</strong></p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<p>Nếu bạn muốn m&igrave;nh:</p>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Gợi &yacute; <strong>qu&aacute;n ăn ngon ở Pleiku</strong></p>\r\n	</li>\r\n	<li>\r\n	<p>Hay chọn <strong>đặc sản dễ mang đi xa</strong></p>\r\n	</li>\r\n	<li>\r\n	<p>Hoặc ăn theo kiểu <strong>địa phương &iacute;t người biết</strong></p>\r\n	</li>\r\n</ul>', 'Gia Lai, Biển hồ, Phố núi Tây Nguyên, Món ngon - đặc sản cao nguyên', 'Gia Lai, Pleiku, món ngon núi rừng, đặc sản tây nguyên, phố núi tình yêu', 'Gia Lai nổi bật với vẻ đẹp hùng vĩ của núi rừng và bản sắc văn hóa đặc trưng của các dân tộc thiểu số. Với những món ăn - thức uống đậm chất hoang sơ của núi rừng', NULL, NULL, 44, NULL, 1, 1, NULL, NULL, NULL),
	(11, 'Đà lạt', 'da-lat', '<strong>Gia Lai</strong>&nbsp;l&agrave; một&nbsp;<a href="https://vi.wikipedia.org/wiki/T%E1%BB%89nh_th%C3%A0nh_Vi%E1%BB%87t_Nam" title="Tỉnh thành Việt Nam">tỉnh</a>&nbsp;nằm ở khu vực&nbsp;<a href="https://vi.wikipedia.org/wiki/Duy%C3%AAn_h%E1%BA%A3i_Nam_Trung_B%E1%BB%99" title="Duyên hải Nam Trung Bộ">duy&ecirc;n hải Nam Trung bộ</a>&nbsp;v&agrave;&nbsp;<a href="https://vi.wikipedia.org/wiki/T%C3%A2y_Nguy%C3%AAn" title="Tây Nguyên">T&acirc;y Nguy&ecirc;n</a>,&nbsp;<a href="https://vi.wikipedia.org/wiki/Mi%E1%BB%81n_Trung" title="Miền Trung">miền Trung</a>&nbsp;<a href="https://vi.wikipedia.org/wiki/Vi%E1%BB%87t_Nam" title="Việt Nam">Việt Nam</a>&nbsp;v&agrave; l&agrave; tỉnh c&oacute; diện t&iacute;ch lớn thứ hai&nbsp;<a href="https://vi.wikipedia.org/wiki/Vi%E1%BB%87t_Nam" title="Việt Nam">Việt Nam</a>.<sup><a href="https://vi.wikipedia.org/wiki/Gia_Lai#cite_note-3">[3]</a></sup>&nbsp;<a href="https://vi.wikipedia.org/wiki/T%E1%BB%89nh_l%E1%BB%B5_(Vi%E1%BB%87t_Nam)" title="Tỉnh lỵ (Việt Nam)">Trung t&acirc;m h&agrave;nh ch&iacute;nh</a>&nbsp;của tỉnh l&agrave; phường&nbsp;<a href="https://vi.wikipedia.org/wiki/Quy_Nh%C6%A1n" title="Quy Nhơn">Quy Nhơn</a>.', '<p>Nguồn gốc t&ecirc;n gọi Gia Lai bắt nguồn từ chữ&nbsp;<a href="https://vi.wikipedia.org/wiki/Ng%C6%B0%E1%BB%9Di_Gia_Rai" title="Người Gia Rai">Jarai</a>, t&ecirc;n gọi của một d&acirc;n tộc thiểu số trong tỉnh, c&aacute;ch gọi n&agrave;y vẫn c&ograve;n giữ trong tiếng của người &Ecirc;-đ&ecirc;, Ba Na, L&agrave;o, Th&aacute;i Lan v&agrave; Campuchia để gọi v&ugrave;ng đất n&agrave;y l&agrave; Jarai, Charay c&oacute; nghĩa l&agrave; v&ugrave;ng đất của người Jarai, c&oacute; lẽ &aacute;m chỉ v&ugrave;ng đất của&nbsp;<a href="https://vi.wikipedia.org/wiki/Th%E1%BB%A7y_X%C3%A1" title="Thủy Xá">Thủy X&aacute;</a>&nbsp;v&agrave;&nbsp;<a href="https://vi.wikipedia.org/wiki/H%E1%BB%8Fa_X%C3%A1" title="Hỏa Xá">Hỏa X&aacute;</a>&nbsp;thuộc&nbsp;<a href="https://vi.wikipedia.org/wiki/Ti%E1%BB%83u_qu%E1%BB%91c_Jarai" title="Tiểu quốc Jarai">tiểu quốc Jarai</a>&nbsp;xưa.</p>\r\n\r\n<p>Gia Lai l&agrave; một tỉnh nằm ở cả v&ugrave;ng n&uacute;i v&agrave; ven biển, nằm ở&nbsp;<a href="https://vi.wikipedia.org/wiki/Nam_Trung_B%E1%BB%99" title="Nam Trung Bộ">Nam Trung Bộ</a>&nbsp;với độ cao trung b&igrave;nh từ 700 - 800&nbsp;<a href="https://vi.wikipedia.org/wiki/M%C3%A9t" title="Mét">m&eacute;t</a>&nbsp;so với mực nước biển đối với v&ugrave;ng n&uacute;i v&agrave; 0 - 30&nbsp;<a href="https://vi.wikipedia.org/wiki/M%C3%A9t" title="Mét">m&eacute;t</a>&nbsp;đối với đồng bằng. Gia Lai c&aacute;ch&nbsp;<a href="https://vi.wikipedia.org/wiki/H%C3%A0_N%E1%BB%99i" title="Hà Nội">H&agrave; Nội</a>&nbsp;1.120&nbsp;km, c&aacute;ch&nbsp;<a href="https://vi.wikipedia.org/wiki/%C4%90%C3%A0_N%E1%BA%B5ng" title="Đà Nẵng">Đ&agrave; Nẵng</a>&nbsp;396&nbsp;km, c&aacute;ch&nbsp;<a href="https://vi.wikipedia.org/wiki/Th%C3%A0nh_ph%E1%BB%91_H%E1%BB%93_Ch%C3%AD_Minh" title="Thành phố Hồ Chí Minh">Th&agrave;nh phố Hồ Ch&iacute; Minh</a>&nbsp;491&nbsp;km.</p>\r\n\r\n<ul>\r\n	<li>Ph&iacute;a đ&ocirc;ng gi&aacute;p&nbsp;<a href="https://vi.wikipedia.org/wiki/Bi%E1%BB%83n_%C4%90%C3%B4ng" title="Biển Đông">Biển Đ&ocirc;ng</a></li>\r\n	<li>Ph&iacute;a t&acirc;y gi&aacute;p tỉnh&nbsp;<a href="https://vi.wikipedia.org/wiki/Ratanakiri" title="Ratanakiri">Ratanakiri</a>,&nbsp;<a href="https://vi.wikipedia.org/wiki/Campuchia" title="Campuchia">Campuchia</a></li>\r\n	<li>Ph&iacute;a nam gi&aacute;p tỉnh&nbsp;<a href="https://vi.wikipedia.org/wiki/%C4%90%E1%BA%AFk_L%E1%BA%AFk" title="Đắk Lắk">Đắk Lắk</a></li>\r\n	<li>Ph&iacute;a bắc gi&aacute;p tỉnh&nbsp;<a href="https://vi.wikipedia.org/wiki/Qu%E1%BA%A3ng_Ng%C3%A3i" title="Quảng Ngãi">Quảng Ng&atilde;i</a>.</li>\r\n</ul>\r\n\r\n<h2><br />\r\nĐặc sản m&oacute;n ngon Gia lai.&nbsp;</h2>\r\n\r\n<h3>🐄 <strong>B&ograve; một nắng Kr&ocirc;ng Pa</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Thịt b&ograve; phơi đ&uacute;ng 1 nắng, khi nướng l&ecirc;n thơm lừng</p>\r\n	</li>\r\n	<li>\r\n	<p>Chấm <strong>muối kiến v&agrave;ng</strong> chua cay mặn ngọt cực cuốn<br />\r\n	👉 Đ&acirc;y l&agrave; <strong>đặc sản nổi tiếng nhất Gia Lai</strong></p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🐔 <strong>G&agrave; nướng cơm lam</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>G&agrave; thả vườn ướp sả &ndash; mật ong &ndash; l&aacute; rừng</p>\r\n	</li>\r\n	<li>\r\n	<p>Ăn k&egrave;m cơm lam dẻo thơm trong ống tre</p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🐖 <strong>Heo rừng nướng / heo mọi</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Thịt chắc, &iacute;t mỡ</p>\r\n	</li>\r\n	<li>\r\n	<p>Thường nướng than hoặc hấp l&aacute; rừng</p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<h2>🍜 M&Oacute;N NƯỚC &ndash; B&Uacute;N &ndash; PHỞ</h2>\r\n\r\n<h3>🍜 <strong>Phở kh&ocirc; Gia Lai (phở hai t&ocirc;)</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>1 t&ocirc; b&aacute;nh phở trộn + 1 t&ocirc; nước l&egrave;o ri&ecirc;ng</p>\r\n	</li>\r\n	<li>\r\n	<p>C&oacute; thịt g&agrave; / b&ograve;, h&agrave;nh phi, đậu phộng<br />\r\n	👉 M&oacute;n n&agrave;y người Gia Lai cực tự h&agrave;o lu&ocirc;n 💖</p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🍲 <strong>B&uacute;n mắm cua</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>M&ugrave;i hơi nặng nhưng ăn l&agrave; nghiện</p>\r\n	</li>\r\n	<li>\r\n	<p>C&oacute; da heo, chả, rau sống đầy &uacute; ụ</p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<h2>🧂 M&Oacute;N CHẤM &ndash; ĂN VẶT</h2>\r\n\r\n<h3>🐜 <strong>Muối kiến v&agrave;ng</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>L&agrave;m từ kiến rừng rang + muối + ớt</p>\r\n	</li>\r\n	<li>\r\n	<p>Chấm b&ograve;, tr&aacute;i c&acirc;y, cơm lam đều ngon</p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🌶 <strong>Muối l&aacute; &eacute;</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Cay thơm đặc trưng</p>\r\n	</li>\r\n	<li>\r\n	<p>Thường ăn k&egrave;m thịt nướng</p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<h2>🍰 ĐẶC SẢN MUA VỀ L&Agrave;M QU&Agrave;</h2>\r\n\r\n<ul>\r\n	<li>\r\n	<p>☕ <strong>C&agrave; ph&ecirc; Pleiku</strong> &ndash; đậm vị, thơm l&acirc;u</p>\r\n	</li>\r\n	<li>\r\n	<p>🍯 <strong>Mật ong rừng Gia Lai</strong></p>\r\n	</li>\r\n	<li>\r\n	<p>🌶 <strong>Ti&ecirc;u Chư S&ecirc;</strong> &ndash; nổi tiếng cả nước</p>\r\n	</li>\r\n	<li>\r\n	<p>🥓 <strong>B&ograve; một nắng đ&oacute;ng g&oacute;i</strong></p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<p>Nếu bạn muốn m&igrave;nh:</p>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Gợi &yacute; <strong>qu&aacute;n ăn ngon ở Pleiku</strong></p>\r\n	</li>\r\n	<li>\r\n	<p>Hay chọn <strong>đặc sản dễ mang đi xa</strong></p>\r\n	</li>\r\n	<li>\r\n	<p>Hoặc ăn theo kiểu <strong>địa phương &iacute;t người biết</strong></p>\r\n	</li>\r\n</ul>', 'Gia Lai, Biển hồ, Phố núi Tây Nguyên, Món ngon - đặc sản cao nguyên', 'Gia Lai, Pleiku, món ngon núi rừng, đặc sản tây nguyên, phố núi tình yêu', 'Gia Lai nổi bật với vẻ đẹp hùng vĩ của núi rừng và bản sắc văn hóa đặc trưng của các dân tộc thiểu số. Với những món ăn - thức uống đậm chất hoang sơ của núi rừng', NULL, NULL, 45, NULL, 1, 1, NULL, NULL, NULL),
	(12, 'Sài Gòn', 'sai-gon', '<strong>Gia Lai</strong>&nbsp;l&agrave; một&nbsp;<a href="https://vi.wikipedia.org/wiki/T%E1%BB%89nh_th%C3%A0nh_Vi%E1%BB%87t_Nam" title="Tỉnh thành Việt Nam">tỉnh</a>&nbsp;nằm ở khu vực&nbsp;<a href="https://vi.wikipedia.org/wiki/Duy%C3%AAn_h%E1%BA%A3i_Nam_Trung_B%E1%BB%99" title="Duyên hải Nam Trung Bộ">duy&ecirc;n hải Nam Trung bộ</a>&nbsp;v&agrave;&nbsp;<a href="https://vi.wikipedia.org/wiki/T%C3%A2y_Nguy%C3%AAn" title="Tây Nguyên">T&acirc;y Nguy&ecirc;n</a>,&nbsp;<a href="https://vi.wikipedia.org/wiki/Mi%E1%BB%81n_Trung" title="Miền Trung">miền Trung</a>&nbsp;<a href="https://vi.wikipedia.org/wiki/Vi%E1%BB%87t_Nam" title="Việt Nam">Việt Nam</a>&nbsp;v&agrave; l&agrave; tỉnh c&oacute; diện t&iacute;ch lớn thứ hai&nbsp;<a href="https://vi.wikipedia.org/wiki/Vi%E1%BB%87t_Nam" title="Việt Nam">Việt Nam</a>.<sup><a href="https://vi.wikipedia.org/wiki/Gia_Lai#cite_note-3">[3]</a></sup>&nbsp;<a href="https://vi.wikipedia.org/wiki/T%E1%BB%89nh_l%E1%BB%B5_(Vi%E1%BB%87t_Nam)" title="Tỉnh lỵ (Việt Nam)">Trung t&acirc;m h&agrave;nh ch&iacute;nh</a>&nbsp;của tỉnh l&agrave; phường&nbsp;<a href="https://vi.wikipedia.org/wiki/Quy_Nh%C6%A1n" title="Quy Nhơn">Quy Nhơn</a>.', '<p>Nguồn gốc t&ecirc;n gọi Gia Lai bắt nguồn từ chữ&nbsp;<a href="https://vi.wikipedia.org/wiki/Ng%C6%B0%E1%BB%9Di_Gia_Rai" title="Người Gia Rai">Jarai</a>, t&ecirc;n gọi của một d&acirc;n tộc thiểu số trong tỉnh, c&aacute;ch gọi n&agrave;y vẫn c&ograve;n giữ trong tiếng của người &Ecirc;-đ&ecirc;, Ba Na, L&agrave;o, Th&aacute;i Lan v&agrave; Campuchia để gọi v&ugrave;ng đất n&agrave;y l&agrave; Jarai, Charay c&oacute; nghĩa l&agrave; v&ugrave;ng đất của người Jarai, c&oacute; lẽ &aacute;m chỉ v&ugrave;ng đất của&nbsp;<a href="https://vi.wikipedia.org/wiki/Th%E1%BB%A7y_X%C3%A1" title="Thủy Xá">Thủy X&aacute;</a>&nbsp;v&agrave;&nbsp;<a href="https://vi.wikipedia.org/wiki/H%E1%BB%8Fa_X%C3%A1" title="Hỏa Xá">Hỏa X&aacute;</a>&nbsp;thuộc&nbsp;<a href="https://vi.wikipedia.org/wiki/Ti%E1%BB%83u_qu%E1%BB%91c_Jarai" title="Tiểu quốc Jarai">tiểu quốc Jarai</a>&nbsp;xưa.</p>\r\n\r\n<p>Gia Lai l&agrave; một tỉnh nằm ở cả v&ugrave;ng n&uacute;i v&agrave; ven biển, nằm ở&nbsp;<a href="https://vi.wikipedia.org/wiki/Nam_Trung_B%E1%BB%99" title="Nam Trung Bộ">Nam Trung Bộ</a>&nbsp;với độ cao trung b&igrave;nh từ 700 - 800&nbsp;<a href="https://vi.wikipedia.org/wiki/M%C3%A9t" title="Mét">m&eacute;t</a>&nbsp;so với mực nước biển đối với v&ugrave;ng n&uacute;i v&agrave; 0 - 30&nbsp;<a href="https://vi.wikipedia.org/wiki/M%C3%A9t" title="Mét">m&eacute;t</a>&nbsp;đối với đồng bằng. Gia Lai c&aacute;ch&nbsp;<a href="https://vi.wikipedia.org/wiki/H%C3%A0_N%E1%BB%99i" title="Hà Nội">H&agrave; Nội</a>&nbsp;1.120&nbsp;km, c&aacute;ch&nbsp;<a href="https://vi.wikipedia.org/wiki/%C4%90%C3%A0_N%E1%BA%B5ng" title="Đà Nẵng">Đ&agrave; Nẵng</a>&nbsp;396&nbsp;km, c&aacute;ch&nbsp;<a href="https://vi.wikipedia.org/wiki/Th%C3%A0nh_ph%E1%BB%91_H%E1%BB%93_Ch%C3%AD_Minh" title="Thành phố Hồ Chí Minh">Th&agrave;nh phố Hồ Ch&iacute; Minh</a>&nbsp;491&nbsp;km.</p>\r\n\r\n<ul>\r\n	<li>Ph&iacute;a đ&ocirc;ng gi&aacute;p&nbsp;<a href="https://vi.wikipedia.org/wiki/Bi%E1%BB%83n_%C4%90%C3%B4ng" title="Biển Đông">Biển Đ&ocirc;ng</a></li>\r\n	<li>Ph&iacute;a t&acirc;y gi&aacute;p tỉnh&nbsp;<a href="https://vi.wikipedia.org/wiki/Ratanakiri" title="Ratanakiri">Ratanakiri</a>,&nbsp;<a href="https://vi.wikipedia.org/wiki/Campuchia" title="Campuchia">Campuchia</a></li>\r\n	<li>Ph&iacute;a nam gi&aacute;p tỉnh&nbsp;<a href="https://vi.wikipedia.org/wiki/%C4%90%E1%BA%AFk_L%E1%BA%AFk" title="Đắk Lắk">Đắk Lắk</a></li>\r\n	<li>Ph&iacute;a bắc gi&aacute;p tỉnh&nbsp;<a href="https://vi.wikipedia.org/wiki/Qu%E1%BA%A3ng_Ng%C3%A3i" title="Quảng Ngãi">Quảng Ng&atilde;i</a>.</li>\r\n</ul>\r\n\r\n<h2><br />\r\nĐặc sản m&oacute;n ngon Gia lai.&nbsp;</h2>\r\n\r\n<h3>🐄 <strong>B&ograve; một nắng Kr&ocirc;ng Pa</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Thịt b&ograve; phơi đ&uacute;ng 1 nắng, khi nướng l&ecirc;n thơm lừng</p>\r\n	</li>\r\n	<li>\r\n	<p>Chấm <strong>muối kiến v&agrave;ng</strong> chua cay mặn ngọt cực cuốn<br />\r\n	👉 Đ&acirc;y l&agrave; <strong>đặc sản nổi tiếng nhất Gia Lai</strong></p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🐔 <strong>G&agrave; nướng cơm lam</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>G&agrave; thả vườn ướp sả &ndash; mật ong &ndash; l&aacute; rừng</p>\r\n	</li>\r\n	<li>\r\n	<p>Ăn k&egrave;m cơm lam dẻo thơm trong ống tre</p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🐖 <strong>Heo rừng nướng / heo mọi</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Thịt chắc, &iacute;t mỡ</p>\r\n	</li>\r\n	<li>\r\n	<p>Thường nướng than hoặc hấp l&aacute; rừng</p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<h2>🍜 M&Oacute;N NƯỚC &ndash; B&Uacute;N &ndash; PHỞ</h2>\r\n\r\n<h3>🍜 <strong>Phở kh&ocirc; Gia Lai (phở hai t&ocirc;)</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>1 t&ocirc; b&aacute;nh phở trộn + 1 t&ocirc; nước l&egrave;o ri&ecirc;ng</p>\r\n	</li>\r\n	<li>\r\n	<p>C&oacute; thịt g&agrave; / b&ograve;, h&agrave;nh phi, đậu phộng<br />\r\n	👉 M&oacute;n n&agrave;y người Gia Lai cực tự h&agrave;o lu&ocirc;n 💖</p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🍲 <strong>B&uacute;n mắm cua</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>M&ugrave;i hơi nặng nhưng ăn l&agrave; nghiện</p>\r\n	</li>\r\n	<li>\r\n	<p>C&oacute; da heo, chả, rau sống đầy &uacute; ụ</p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<h2>🧂 M&Oacute;N CHẤM &ndash; ĂN VẶT</h2>\r\n\r\n<h3>🐜 <strong>Muối kiến v&agrave;ng</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>L&agrave;m từ kiến rừng rang + muối + ớt</p>\r\n	</li>\r\n	<li>\r\n	<p>Chấm b&ograve;, tr&aacute;i c&acirc;y, cơm lam đều ngon</p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🌶 <strong>Muối l&aacute; &eacute;</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Cay thơm đặc trưng</p>\r\n	</li>\r\n	<li>\r\n	<p>Thường ăn k&egrave;m thịt nướng</p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<h2>🍰 ĐẶC SẢN MUA VỀ L&Agrave;M QU&Agrave;</h2>\r\n\r\n<ul>\r\n	<li>\r\n	<p>☕ <strong>C&agrave; ph&ecirc; Pleiku</strong> &ndash; đậm vị, thơm l&acirc;u</p>\r\n	</li>\r\n	<li>\r\n	<p>🍯 <strong>Mật ong rừng Gia Lai</strong></p>\r\n	</li>\r\n	<li>\r\n	<p>🌶 <strong>Ti&ecirc;u Chư S&ecirc;</strong> &ndash; nổi tiếng cả nước</p>\r\n	</li>\r\n	<li>\r\n	<p>🥓 <strong>B&ograve; một nắng đ&oacute;ng g&oacute;i</strong></p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<p>Nếu bạn muốn m&igrave;nh:</p>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Gợi &yacute; <strong>qu&aacute;n ăn ngon ở Pleiku</strong></p>\r\n	</li>\r\n	<li>\r\n	<p>Hay chọn <strong>đặc sản dễ mang đi xa</strong></p>\r\n	</li>\r\n	<li>\r\n	<p>Hoặc ăn theo kiểu <strong>địa phương &iacute;t người biết</strong></p>\r\n	</li>\r\n</ul>', 'Gia Lai, Biển hồ, Phố núi Tây Nguyên, Món ngon - đặc sản cao nguyên', 'Gia Lai, Pleiku, món ngon núi rừng, đặc sản tây nguyên, phố núi tình yêu', 'Gia Lai nổi bật với vẻ đẹp hùng vĩ của núi rừng và bản sắc văn hóa đặc trưng của các dân tộc thiểu số. Với những món ăn - thức uống đậm chất hoang sơ của núi rừng', NULL, NULL, 46, NULL, 1, 1, NULL, NULL, NULL),
	(13, 'Sài Gòn', 'sai-gon', '<strong>Gia Lai</strong>&nbsp;l&agrave; một&nbsp;<a href="https://vi.wikipedia.org/wiki/T%E1%BB%89nh_th%C3%A0nh_Vi%E1%BB%87t_Nam" title="Tỉnh thành Việt Nam">tỉnh</a>&nbsp;nằm ở khu vực&nbsp;<a href="https://vi.wikipedia.org/wiki/Duy%C3%AAn_h%E1%BA%A3i_Nam_Trung_B%E1%BB%99" title="Duyên hải Nam Trung Bộ">duy&ecirc;n hải Nam Trung bộ</a>&nbsp;v&agrave;&nbsp;<a href="https://vi.wikipedia.org/wiki/T%C3%A2y_Nguy%C3%AAn" title="Tây Nguyên">T&acirc;y Nguy&ecirc;n</a>,&nbsp;<a href="https://vi.wikipedia.org/wiki/Mi%E1%BB%81n_Trung" title="Miền Trung">miền Trung</a>&nbsp;<a href="https://vi.wikipedia.org/wiki/Vi%E1%BB%87t_Nam" title="Việt Nam">Việt Nam</a>&nbsp;v&agrave; l&agrave; tỉnh c&oacute; diện t&iacute;ch lớn thứ hai&nbsp;<a href="https://vi.wikipedia.org/wiki/Vi%E1%BB%87t_Nam" title="Việt Nam">Việt Nam</a>.<sup><a href="https://vi.wikipedia.org/wiki/Gia_Lai#cite_note-3">[3]</a></sup>&nbsp;<a href="https://vi.wikipedia.org/wiki/T%E1%BB%89nh_l%E1%BB%B5_(Vi%E1%BB%87t_Nam)" title="Tỉnh lỵ (Việt Nam)">Trung t&acirc;m h&agrave;nh ch&iacute;nh</a>&nbsp;của tỉnh l&agrave; phường&nbsp;<a href="https://vi.wikipedia.org/wiki/Quy_Nh%C6%A1n" title="Quy Nhơn">Quy Nhơn</a>.', '<p>Nguồn gốc t&ecirc;n gọi Gia Lai bắt nguồn từ chữ&nbsp;<a href="https://vi.wikipedia.org/wiki/Ng%C6%B0%E1%BB%9Di_Gia_Rai" title="Người Gia Rai">Jarai</a>, t&ecirc;n gọi của một d&acirc;n tộc thiểu số trong tỉnh, c&aacute;ch gọi n&agrave;y vẫn c&ograve;n giữ trong tiếng của người &Ecirc;-đ&ecirc;, Ba Na, L&agrave;o, Th&aacute;i Lan v&agrave; Campuchia để gọi v&ugrave;ng đất n&agrave;y l&agrave; Jarai, Charay c&oacute; nghĩa l&agrave; v&ugrave;ng đất của người Jarai, c&oacute; lẽ &aacute;m chỉ v&ugrave;ng đất của&nbsp;<a href="https://vi.wikipedia.org/wiki/Th%E1%BB%A7y_X%C3%A1" title="Thủy Xá">Thủy X&aacute;</a>&nbsp;v&agrave;&nbsp;<a href="https://vi.wikipedia.org/wiki/H%E1%BB%8Fa_X%C3%A1" title="Hỏa Xá">Hỏa X&aacute;</a>&nbsp;thuộc&nbsp;<a href="https://vi.wikipedia.org/wiki/Ti%E1%BB%83u_qu%E1%BB%91c_Jarai" title="Tiểu quốc Jarai">tiểu quốc Jarai</a>&nbsp;xưa.</p>\r\n\r\n<p>Gia Lai l&agrave; một tỉnh nằm ở cả v&ugrave;ng n&uacute;i v&agrave; ven biển, nằm ở&nbsp;<a href="https://vi.wikipedia.org/wiki/Nam_Trung_B%E1%BB%99" title="Nam Trung Bộ">Nam Trung Bộ</a>&nbsp;với độ cao trung b&igrave;nh từ 700 - 800&nbsp;<a href="https://vi.wikipedia.org/wiki/M%C3%A9t" title="Mét">m&eacute;t</a>&nbsp;so với mực nước biển đối với v&ugrave;ng n&uacute;i v&agrave; 0 - 30&nbsp;<a href="https://vi.wikipedia.org/wiki/M%C3%A9t" title="Mét">m&eacute;t</a>&nbsp;đối với đồng bằng. Gia Lai c&aacute;ch&nbsp;<a href="https://vi.wikipedia.org/wiki/H%C3%A0_N%E1%BB%99i" title="Hà Nội">H&agrave; Nội</a>&nbsp;1.120&nbsp;km, c&aacute;ch&nbsp;<a href="https://vi.wikipedia.org/wiki/%C4%90%C3%A0_N%E1%BA%B5ng" title="Đà Nẵng">Đ&agrave; Nẵng</a>&nbsp;396&nbsp;km, c&aacute;ch&nbsp;<a href="https://vi.wikipedia.org/wiki/Th%C3%A0nh_ph%E1%BB%91_H%E1%BB%93_Ch%C3%AD_Minh" title="Thành phố Hồ Chí Minh">Th&agrave;nh phố Hồ Ch&iacute; Minh</a>&nbsp;491&nbsp;km.</p>\r\n\r\n<ul>\r\n	<li>Ph&iacute;a đ&ocirc;ng gi&aacute;p&nbsp;<a href="https://vi.wikipedia.org/wiki/Bi%E1%BB%83n_%C4%90%C3%B4ng" title="Biển Đông">Biển Đ&ocirc;ng</a></li>\r\n	<li>Ph&iacute;a t&acirc;y gi&aacute;p tỉnh&nbsp;<a href="https://vi.wikipedia.org/wiki/Ratanakiri" title="Ratanakiri">Ratanakiri</a>,&nbsp;<a href="https://vi.wikipedia.org/wiki/Campuchia" title="Campuchia">Campuchia</a></li>\r\n	<li>Ph&iacute;a nam gi&aacute;p tỉnh&nbsp;<a href="https://vi.wikipedia.org/wiki/%C4%90%E1%BA%AFk_L%E1%BA%AFk" title="Đắk Lắk">Đắk Lắk</a></li>\r\n	<li>Ph&iacute;a bắc gi&aacute;p tỉnh&nbsp;<a href="https://vi.wikipedia.org/wiki/Qu%E1%BA%A3ng_Ng%C3%A3i" title="Quảng Ngãi">Quảng Ng&atilde;i</a>.</li>\r\n</ul>\r\n\r\n<h2><br />\r\nĐặc sản m&oacute;n ngon Gia lai.&nbsp;</h2>\r\n\r\n<h3>🐄 <strong>B&ograve; một nắng Kr&ocirc;ng Pa</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Thịt b&ograve; phơi đ&uacute;ng 1 nắng, khi nướng l&ecirc;n thơm lừng</p>\r\n	</li>\r\n	<li>\r\n	<p>Chấm <strong>muối kiến v&agrave;ng</strong> chua cay mặn ngọt cực cuốn<br />\r\n	👉 Đ&acirc;y l&agrave; <strong>đặc sản nổi tiếng nhất Gia Lai</strong></p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🐔 <strong>G&agrave; nướng cơm lam</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>G&agrave; thả vườn ướp sả &ndash; mật ong &ndash; l&aacute; rừng</p>\r\n	</li>\r\n	<li>\r\n	<p>Ăn k&egrave;m cơm lam dẻo thơm trong ống tre</p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🐖 <strong>Heo rừng nướng / heo mọi</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Thịt chắc, &iacute;t mỡ</p>\r\n	</li>\r\n	<li>\r\n	<p>Thường nướng than hoặc hấp l&aacute; rừng</p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<h2>🍜 M&Oacute;N NƯỚC &ndash; B&Uacute;N &ndash; PHỞ</h2>\r\n\r\n<h3>🍜 <strong>Phở kh&ocirc; Gia Lai (phở hai t&ocirc;)</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>1 t&ocirc; b&aacute;nh phở trộn + 1 t&ocirc; nước l&egrave;o ri&ecirc;ng</p>\r\n	</li>\r\n	<li>\r\n	<p>C&oacute; thịt g&agrave; / b&ograve;, h&agrave;nh phi, đậu phộng<br />\r\n	👉 M&oacute;n n&agrave;y người Gia Lai cực tự h&agrave;o lu&ocirc;n 💖</p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🍲 <strong>B&uacute;n mắm cua</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>M&ugrave;i hơi nặng nhưng ăn l&agrave; nghiện</p>\r\n	</li>\r\n	<li>\r\n	<p>C&oacute; da heo, chả, rau sống đầy &uacute; ụ</p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<h2>🧂 M&Oacute;N CHẤM &ndash; ĂN VẶT</h2>\r\n\r\n<h3>🐜 <strong>Muối kiến v&agrave;ng</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>L&agrave;m từ kiến rừng rang + muối + ớt</p>\r\n	</li>\r\n	<li>\r\n	<p>Chấm b&ograve;, tr&aacute;i c&acirc;y, cơm lam đều ngon</p>\r\n	</li>\r\n</ul>\r\n\r\n<h3>🌶 <strong>Muối l&aacute; &eacute;</strong></h3>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Cay thơm đặc trưng</p>\r\n	</li>\r\n	<li>\r\n	<p>Thường ăn k&egrave;m thịt nướng</p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<h2>🍰 ĐẶC SẢN MUA VỀ L&Agrave;M QU&Agrave;</h2>\r\n\r\n<ul>\r\n	<li>\r\n	<p>☕ <strong>C&agrave; ph&ecirc; Pleiku</strong> &ndash; đậm vị, thơm l&acirc;u</p>\r\n	</li>\r\n	<li>\r\n	<p>🍯 <strong>Mật ong rừng Gia Lai</strong></p>\r\n	</li>\r\n	<li>\r\n	<p>🌶 <strong>Ti&ecirc;u Chư S&ecirc;</strong> &ndash; nổi tiếng cả nước</p>\r\n	</li>\r\n	<li>\r\n	<p>🥓 <strong>B&ograve; một nắng đ&oacute;ng g&oacute;i</strong></p>\r\n	</li>\r\n</ul>\r\n\r\n<hr />\r\n<p>Nếu bạn muốn m&igrave;nh:</p>\r\n\r\n<ul>\r\n	<li>\r\n	<p>Gợi &yacute; <strong>qu&aacute;n ăn ngon ở Pleiku</strong></p>\r\n	</li>\r\n	<li>\r\n	<p>Hay chọn <strong>đặc sản dễ mang đi xa</strong></p>\r\n	</li>\r\n	<li>\r\n	<p>Hoặc ăn theo kiểu <strong>địa phương &iacute;t người biết</strong></p>\r\n	</li>\r\n</ul>', 'Gia Lai, Biển hồ, Phố núi Tây Nguyên, Món ngon - đặc sản cao nguyên', 'Gia Lai, Pleiku, món ngon núi rừng, đặc sản tây nguyên, phố núi tình yêu', 'Gia Lai nổi bật với vẻ đẹp hùng vĩ của núi rừng và bản sắc văn hóa đặc trưng của các dân tộc thiểu số. Với những món ăn - thức uống đậm chất hoang sơ của núi rừng', '99', NULL, 100, NULL, 1, 1, NULL, '2026-01-13 08:03:54', '2026-01-13 08:03:54');
