INSERT INTO `product_categories` (`id`, `title`, `slug`, `content`, `parent_id`, `meta_title`, `meta_keywords`, `meta_description`, `icon`, `banner`, `image_id`, `images`, `index`, `active`, `created_at`, `updated_at`, `deleted_at`) VALUES
	(1, 'Đặc sản', 'dac-san', '<strong>Gian h&agrave;ng Đặc sản &ndash; Ngon ba miền</strong><br />\r\nNơi hội tụ tinh hoa ẩm thực Bắc &ndash; Trung &ndash; Nam, mang đến những m&oacute;n đặc sản chuẩn vị qu&ecirc; hương. Từ mặn m&agrave;, đậm đ&agrave; đến ngọt ng&agrave;o, tinh tế, mỗi sản phẩm đều được chọn lọc kỹ lưỡng, đảm bảo chất lượng v&agrave; hương vị truyền thống.<br />\r\nGh&eacute; gian h&agrave;ng Đặc sản Site để thưởng thức, mua sắm v&agrave; mang về những m&oacute;n qu&agrave; đậm đ&agrave; bản sắc ba miền d&agrave;nh tặng người th&acirc;n v&agrave; bạn b&egrave;.', NULL, 'Đặc sản - sản vật quý, món ăn ngon của vùng miền, địa phương', 'Mua bán các món ăn đặc sản, sản vật, món ăn ngon được yêu thích của địa phương', 'Giao hàng, bán các đặc sản, sản vật của địa phương vùng miền. thơm ngon chất lượng nhanh chóng', NULL, '/storage/ngonbamien/GiaLai2-3.jpg', 47, NULL, 1, 1, NULL, '2025-12-21 04:41:06', NULL),
	(2, 'Món ngon', 'mon-ngon', '<strong>Đặc sản</strong>&nbsp;l&agrave; t&ecirc;n gọi chỉ chung về những sản vật, sản phẩm,&nbsp;<a href="https://vi.wikipedia.org/wiki/H%C3%A0ng_h%C3%B3a" title="Hàng hóa">h&agrave;ng h&oacute;a</a>&nbsp;(thường l&agrave;&nbsp;<a href="https://vi.wikipedia.org/wiki/N%C3%B4ng_s%E1%BA%A3n" title="Nông sản">n&ocirc;ng sản</a>) mang t&iacute;nh đặc th&ugrave; hoặc c&oacute; nhiều điểm đặc biệt, ri&ecirc;ng c&oacute; m&agrave; xuất xứ từ những v&ugrave;ng, miền, địa phương v&agrave; tạo n&ecirc;n những n&eacute;t đặc trưng của một v&ugrave;ng, miền hay một địa phương n&agrave;o đ&oacute;. Kh&aacute;i niệm đặc sản cũng kh&ocirc;ng nhất thiết chỉ về những sản phẩm, sản vật được ra đời đầu ti&ecirc;n tại v&ugrave;ng, miền hay&nbsp;<a href="https://vi.wikipedia.org/w/index.php?title=%C4%90%E1%BB%8Ba_ph%C6%B0%C6%A1ng&amp;action=edit&amp;redlink=1" title="Địa phương (trang không tồn tại)">địa phương</a>&nbsp;nhưng n&oacute; mang t&iacute;nh chất th&ocirc;ng dụng, phổ biến tại địa phương hay c&oacute; chất lượng cao hơn hẳn những sản phẩm c&ugrave;ng loại v&agrave; được nh&acirc;n d&acirc;n địa phương coi như sản phẩm truyền thống của địa phương m&igrave;nh.', NULL, 'Đặc sản - sản vật quý, món ăn ngon của vùng miền, địa phương', 'Mua bán các món ăn đặc sản, sản vật, món ăn ngon được yêu thích của địa phương', 'Giao hàng, bán các đặc sản, sản vật của địa phương vùng miền. thơm ngon chất lượng nhanh chóng', NULL, NULL, 48, NULL, 1, 1, NULL, '2025-12-21 04:44:32', NULL),
	(3, 'Cà Phê', 'ca-phe', '<strong>Đặc sản</strong>&nbsp;l&agrave; t&ecirc;n gọi chỉ chung về những sản vật, sản phẩm,&nbsp;<a href="https://vi.wikipedia.org/wiki/H%C3%A0ng_h%C3%B3a" title="Hàng hóa">h&agrave;ng h&oacute;a</a>&nbsp;(thường l&agrave;&nbsp;<a href="https://vi.wikipedia.org/wiki/N%C3%B4ng_s%E1%BA%A3n" title="Nông sản">n&ocirc;ng sản</a>) mang t&iacute;nh đặc th&ugrave; hoặc c&oacute; nhiều điểm đặc biệt, ri&ecirc;ng c&oacute; m&agrave; xuất xứ từ những v&ugrave;ng, miền, địa phương v&agrave; tạo n&ecirc;n những n&eacute;t đặc trưng của một v&ugrave;ng, miền hay một địa phương n&agrave;o đ&oacute;. Kh&aacute;i niệm đặc sản cũng kh&ocirc;ng nhất thiết chỉ về những sản phẩm, sản vật được ra đời đầu ti&ecirc;n tại v&ugrave;ng, miền hay&nbsp;<a href="https://vi.wikipedia.org/w/index.php?title=%C4%90%E1%BB%8Ba_ph%C6%B0%C6%A1ng&amp;action=edit&amp;redlink=1" title="Địa phương (trang không tồn tại)">địa phương</a>&nbsp;nhưng n&oacute; mang t&iacute;nh chất th&ocirc;ng dụng, phổ biến tại địa phương hay c&oacute; chất lượng cao hơn hẳn những sản phẩm c&ugrave;ng loại v&agrave; được nh&acirc;n d&acirc;n địa phương coi như sản phẩm truyền thống của địa phương m&igrave;nh.', NULL, 'Đặc sản - sản vật quý, món ăn ngon của vùng miền, địa phương', 'Mua bán các món ăn đặc sản, sản vật, món ăn ngon được yêu thích của địa phương', 'Giao hàng, bán các đặc sản, sản vật của địa phương vùng miền. thơm ngon chất lượng nhanh chóng', NULL, NULL, 49, NULL, 1, 1, NULL, '2025-12-21 04:46:59', NULL),
	(4, 'Quả tặng', 'qua-tang', '<strong>Đặc sản</strong>&nbsp;l&agrave; t&ecirc;n gọi chỉ chung về những sản vật, sản phẩm,&nbsp;<a href="https://vi.wikipedia.org/wiki/H%C3%A0ng_h%C3%B3a" title="Hàng hóa">h&agrave;ng h&oacute;a</a>&nbsp;(thường l&agrave;&nbsp;<a href="https://vi.wikipedia.org/wiki/N%C3%B4ng_s%E1%BA%A3n" title="Nông sản">n&ocirc;ng sản</a>) mang t&iacute;nh đặc th&ugrave; hoặc c&oacute; nhiều điểm đặc biệt, ri&ecirc;ng c&oacute; m&agrave; xuất xứ từ những v&ugrave;ng, miền, địa phương v&agrave; tạo n&ecirc;n những n&eacute;t đặc trưng của một v&ugrave;ng, miền hay một địa phương n&agrave;o đ&oacute;. Kh&aacute;i niệm đặc sản cũng kh&ocirc;ng nhất thiết chỉ về những sản phẩm, sản vật được ra đời đầu ti&ecirc;n tại v&ugrave;ng, miền hay&nbsp;<a href="https://vi.wikipedia.org/w/index.php?title=%C4%90%E1%BB%8Ba_ph%C6%B0%C6%A1ng&amp;action=edit&amp;redlink=1" title="Địa phương (trang không tồn tại)">địa phương</a>&nbsp;nhưng n&oacute; mang t&iacute;nh chất th&ocirc;ng dụng, phổ biến tại địa phương hay c&oacute; chất lượng cao hơn hẳn những sản phẩm c&ugrave;ng loại v&agrave; được nh&acirc;n d&acirc;n địa phương coi như sản phẩm truyền thống của địa phương m&igrave;nh.', NULL, 'Đặc sản - sản vật quý, món ăn ngon của vùng miền, địa phương', 'Mua bán các món ăn đặc sản, sản vật, món ăn ngon được yêu thích của địa phương', 'Giao hàng, bán các đặc sản, sản vật của địa phương vùng miền. thơm ngon chất lượng nhanh chóng', NULL, NULL, 56, NULL, 1, 1, NULL, '2025-12-27 12:14:09', NULL),
